    def _sync_adh_from_mu_visc(self):
        """Synchronize μ_adh conditions from μ_visc tab parameters."""
        try:
            # Sync temperature
            if hasattr(self, 'mu_calc_temp_var'):
                self.adh_calc_temp_var.set(self.mu_calc_temp_var.get())
            elif hasattr(self, 'temperature_var'):
                self.adh_calc_temp_var.set(self.temperature_var.get())

            # Sync pressure
            if hasattr(self, 'mu_sigma0_var') and self.mu_sigma0_var.get().strip():
                self.adh_p0_var.set(self.mu_sigma0_var.get())
            elif hasattr(self, 'sigma_0_var'):
                self.adh_p0_var.set(self.sigma_0_var.get())

            # Sync T_ref from Tab 2 aT data
            if hasattr(self, 'persson_aT_data') and self.persson_aT_data is not None:
                T_ref_C = self.persson_aT_data.get('T_ref', None)
                if T_ref_C is not None:
                    T_ref_K = T_ref_C + 273.15
                    self.adh_T_ref_var.set(f"{T_ref_K:.2f}")

            # Check A/A0 availability
            if self.mu_visc_results is not None and 'P_qmax' in self.mu_visc_results:
                P_qmax = self.mu_visc_results['P_qmax']
                v = self.mu_visc_results['v']
                self.adh_area_status_var.set(
                    f"A/A0: {np.min(P_qmax):.4f} ~ {np.max(P_qmax):.4f} ({len(v)}점)")
                self.adh_sync_status_var.set("동기화 완료")
            else:
                self.adh_area_status_var.set("A/A0: μ_visc 결과 없음")
                self.adh_sync_status_var.set("A/A0 없음 - μ_visc 먼저 계산")

            self._show_status("μ_visc 조건이 μ_adh 탭에 동기화되었습니다.", 'success')
        except Exception as e:
            self._show_status(f"동기화 실패: {str(e)}", 'warning')

    def _calculate_mu_adh(self):
        """Calculate adhesion friction coefficient μ_adh.

        Algorithm (4 steps):
        Step 1: Arrhenius adhesion shift factor aT'
                aT' = exp[(ε / k_B) × (1/T - 1/T_ref)]
        Step 2: Temperature-corrected effective velocity
                v_eff = v × aT'
        Step 3: Effective adhesion shear stress (Gaussian master curve)
                τ_f = τ_f0 × exp[-c × (log10(v_eff / v₀*))²]
        Step 4: Adhesion friction coefficient
                μ_adh = (τ_f / p₀) × A_ratio

        When calculation temperature differs from μ_visc temperature,
        automatically re-runs temperature shift + μ_visc recalculation
        so that μ_visc and A/A0 data are consistent with the new temperature.
        """
        try:
            self.adh_calc_button.config(state='disabled')
            self.adh_progress_var.set(0)
            self.status_var.set("μ_adh 계산 중...")
            self.root.update()

            # ── Auto-sync T_ref from Tab 2 aT data ──
            if hasattr(self, 'persson_aT_data') and self.persson_aT_data is not None:
                T_ref_C = self.persson_aT_data.get('T_ref', None)
                if T_ref_C is not None:
                    T_ref_K = T_ref_C + 273.15
                    self.adh_T_ref_var.set(f"{T_ref_K:.2f}")

            # ── Read parameters ──
            tau_f0 = float(self.adh_tau_f0_var.get()) * 1e6     # MPa → Pa
            v0_star = float(self.adh_v0_star_var.get())          # m/s
            c = float(self.adh_c_var.get())                      # dimensionless
            epsilon = float(self.adh_epsilon_var.get())           # eV
            T_ref = float(self.adh_T_ref_var.get())              # K
            k_B = 8.6173e-5                                      # eV/K (Boltzmann)

            T_calc_C = float(self.adh_calc_temp_var.get())       # °C
            T = T_calc_C + 273.15                                # K

            p0_str = self.adh_p0_var.get().strip()
            if not p0_str:
                # Try to sync from sigma_0_var
                if hasattr(self, 'sigma_0_var'):
                    p0_str = self.sigma_0_var.get()
                    self.adh_p0_var.set(p0_str)
            p0 = float(p0_str) * 1e6                            # MPa → Pa

            if p0 <= 0:
                self._show_status("p₀(명목 접촉 압력)는 양수여야 합니다.", 'warning')
                self.adh_calc_button.config(state='normal')
                return

            # ── Auto temperature shift: recalculate μ_visc if temperature changed ──
            # When calculation temperature differs from μ_visc calculation temperature,
            # automatically trigger temperature shift + G recalculation + μ_visc recalculation.
            # This ensures μ_visc and A/A0 are always consistent with the current temperature.
            # Note: After fitting is completed (_adh_fitting_completed=True), this is NOT
            # re-fitting. The fitted parameters (τ_f0, v₀*, c) are fixed. Temperature
            # changes only shift the τ_f curve via the Arrhenius factor aT'.
            need_mu_visc_recalc = False
            mu_visc_temp = None
            mu_visc_p0 = None
            if (hasattr(self, 'persson_aT_interp') and self.persson_aT_interp is not None
                    and hasattr(self, 'persson_master_curve') and self.persson_master_curve is not None):
                # Check if temperature differs from what was used for mu_visc
                if hasattr(self, 'current_temp_shift') and self.current_temp_shift is not None:
                    mu_visc_temp = self.current_temp_shift.get('T_target', None)
                elif hasattr(self, 'mu_calc_temp_var'):
                    try:
                        mu_visc_temp = float(self.mu_calc_temp_var.get())
                    except (ValueError, AttributeError):
                        pass

                # Check if pressure differs from what was used for mu_visc
                if hasattr(self, 'mu_sigma0_var'):
                    try:
                        mu_visc_p0 = float(self.mu_sigma0_var.get()) * 1e6  # MPa → Pa
                    except (ValueError, AttributeError):
                        pass

                if mu_visc_temp is not None and abs(T_calc_C - mu_visc_temp) > 0.01:
                    need_mu_visc_recalc = True

                if mu_visc_p0 is not None and abs(p0 - mu_visc_p0) / max(p0, 1e-10) > 0.001:
                    need_mu_visc_recalc = True

            reason_parts = []
            if mu_visc_temp is not None and abs(T_calc_C - mu_visc_temp) > 0.01:
                reason_parts.append(f"온도 {mu_visc_temp:.1f}→{T_calc_C:.1f}°C")
            if mu_visc_p0 is not None and abs(p0 - mu_visc_p0) / max(p0, 1e-10) > 0.001:
                reason_parts.append(f"하중 {mu_visc_p0/1e6:.4g}→{p0/1e6:.4g} MPa")

            if need_mu_visc_recalc:
                reason_str = ", ".join(reason_parts)
                if self._adh_fitting_completed:
                    self.status_var.set(
                        f"변경 감지 ({reason_str}): "
                        f"μ_visc/A/A0 재계산 중 (피팅 파라미터 고정)...")
                else:
                    self.status_var.set(
                        f"변경 감지 ({reason_str}): μ_visc/A/A0 재계산 중...")
                self.root.update()

                # Clear stale mu_visc results before recalculation
                self.mu_visc_results = None

                # Sync the temperature to mu_visc tab
                self.mu_calc_temp_var.set(str(T_calc_C))

                # Sync pressure to mu_visc tab
                p0_MPa_str = f"{p0/1e6:.4g}"
                self.mu_sigma0_var.set(p0_MPa_str)
                if hasattr(self, 'sigma_0_var'):
                    self.sigma_0_var.set(p0_MPa_str)

                # Apply temperature shift (recalculates G(q,v) with shifted master curve)
                try:
                    self._apply_temperature_shift()
                except Exception as e_shift:
                    print(f"Temperature shift error: {e_shift}")

                # Recalculate μ_visc at new temperature
                try:
                    self._calculate_mu_visc()
                except Exception as e_mu:
                    print(f"μ_visc recalculation error: {e_mu}")

                # Update A/A0 status display
                if self.mu_visc_results is not None and 'P_qmax' in self.mu_visc_results:
                    P_qmax = self.mu_visc_results['P_qmax']
                    self.adh_area_status_var.set(
                        f"A/A0: {np.min(P_qmax):.4f} ~ {np.max(P_qmax):.4f} "
                        f"({len(self.mu_visc_results['v'])}점, T={T_calc_C:.1f}°C)")

                self.status_var.set("μ_adh 계산 계속...")
                self.root.update()

            # ── Determine velocity array and A/A0 ──
            area_source = self.adh_area_source_var.get()

            if area_source == "from_mu_visc":
                if self.mu_visc_results is None or 'P_qmax' not in self.mu_visc_results:
                    self._show_status(
                        "μ_visc 결과가 없습니다.\n\n"
                        "먼저 μ_visc 탭에서 계산을 실행하거나,\n"
                        "'고정값 사용' 옵션을 선택하세요.", 'warning')
                    self.adh_calc_button.config(state='normal')
                    return
                v_array = self.mu_visc_results['v']
                A_ratio = self.mu_visc_results['P_qmax']
            else:
                # Fixed A/A0 value
                fixed_area = float(self.adh_fixed_area_var.get())
                fixed_area = np.clip(fixed_area, 0.0, 1.0)
                if self.mu_visc_results is not None and 'v' in self.mu_visc_results:
                    v_array = self.mu_visc_results['v']
                elif hasattr(self, 'results') and self.results and '2d_results' in self.results:
                    v_array = self.results['2d_results']['v']
                else:
                    # Generate default velocity range
                    v_array = np.logspace(-4, 1, 50)
                A_ratio = np.full(len(v_array), fixed_area)

            n_v = len(v_array)

            self.adh_progress_var.set(10)
            self.root.update()

            # ── Step 1: Arrhenius adhesion shift factor aT' ──
            # 항상 cold (기본 온도) aT_prime 사용.
            # mu_adh 탭은 cold 조건에서 피팅/계산. Hot 효과는 Cold & Hot Branch 탭에서 적용.
            # aT' = exp[(ε / k_B) × (1/T - 1/T_ref)]
            aT_prime = np.exp((epsilon / k_B) * (1.0 / T - 1.0 / T_ref))
            aT_prime_cold = aT_prime

            self.adh_progress_var.set(25)
            self.root.update()

            # ── Step 2: Temperature-corrected effective velocity ──
            # v_eff = v × aT'  (array × array if flash, array × scalar if cold)
            v_eff = v_array * aT_prime

            self.adh_progress_var.set(40)
            self.root.update()

            # ── Step 3: Effective adhesion shear stress (Gaussian) ──
            # τ_f = τ_f0 × exp[-c × (log10(v_eff / v₀*))²]
            log_ratio = np.log10(v_eff / v0_star)
            tau_f = tau_f0 * np.exp(-c * log_ratio**2)

            self.adh_progress_var.set(60)
            self.root.update()

            # ── Step 4: Adhesion friction coefficient ──
            # μ_adh = (τ_f / p₀) × A_ratio
            mu_adh = (tau_f / p0) * A_ratio

            self.adh_progress_var.set(80)
            self.root.update()

            # ── Store results ──
            self.mu_adh_results = {
                'v': v_array,
                'mu_adh': mu_adh,
                'tau_f': tau_f,            # Pa (cold)
                'tau_f_cold': None,        # not needed (everything is cold)
                'A_ratio': A_ratio,
                'aT_prime': aT_prime,      # scalar (cold)
                'aT_prime_cold': aT_prime_cold,
                'v_eff': v_eff,
                'use_flash': False,
                'params': {
                    'tau_f0': tau_f0,       # Pa
                    'v0_star': v0_star,
                    'c': c,
                    'epsilon': epsilon,
                    'T_ref': T_ref,
                    'T': T,
                    'p0': p0,
                    'area_source': area_source,
                }
            }

            # ── Update plots ──
            self._update_mu_adh_plots()

            # ── Update result text ──
            self.adh_result_text.delete(1.0, tk.END)
            self.adh_result_text.insert(tk.END, "=" * 40 + "\n")
            self.adh_result_text.insert(tk.END, "μ_adh 계산 결과 (Cold, 점착 마찰)\n")
            self.adh_result_text.insert(tk.END, "=" * 40 + "\n\n")

            self.adh_result_text.insert(tk.END, "[파라미터]\n")
            self.adh_result_text.insert(tk.END, f"  τ_f0 = {tau_f0/1e6:.2f} MPa\n")
            self.adh_result_text.insert(tk.END, f"  v₀*  = {v0_star:.4f} m/s\n")
            self.adh_result_text.insert(tk.END, f"  c    = {c:.4f}\n")
            self.adh_result_text.insert(tk.END, f"  ε    = {epsilon:.4f} eV\n")
            self.adh_result_text.insert(tk.END, f"  T_ref= {T_ref:.2f} K\n")
            self.adh_result_text.insert(tk.END, f"  T    = {T:.2f} K ({T_calc_C:.1f}°C)\n")
            self.adh_result_text.insert(tk.END, f"  p₀   = {p0/1e6:.3f} MPa\n")
            self.adh_result_text.insert(tk.END, f"  k_B  = {k_B:.4e} eV/K\n\n")

            self.adh_result_text.insert(tk.END, "[중간 계산값]\n")
            self.adh_result_text.insert(tk.END, f"  aT' (Arrhenius, Cold) = {aT_prime:.6e}\n")
            self.adh_result_text.insert(tk.END, f"    exp[(ε/k_B)×(1/T - 1/T_ref)]\n")
            self.adh_result_text.insert(tk.END, f"    = exp[({epsilon}/{k_B:.4e})×({1/T:.6f} - {1/T_ref:.6f})]\n")
            self.adh_result_text.insert(tk.END, f"  A/A0 출처: {'μ_visc 결과' if area_source == 'from_mu_visc' else '고정값'}\n")
            self.adh_result_text.insert(tk.END, f"  A/A0 범위: {np.min(A_ratio):.6f} ~ {np.max(A_ratio):.6f}\n\n")

            # Smart formatter
            def smart_fmt(val):
                if abs(val) < 0.001 and val != 0:
                    return f'{val:.2e}'
                return f'{val:.4f}'

            self.adh_result_text.insert(tk.END, "[결과]\n")
            mu_min, mu_max = np.min(mu_adh), np.max(mu_adh)
            self.adh_result_text.insert(tk.END, f"  μ_adh 범위: {smart_fmt(mu_min)} ~ {smart_fmt(mu_max)}\n")

            peak_idx = np.argmax(mu_adh)
            peak_mu = mu_adh[peak_idx]
            self.adh_result_text.insert(tk.END, f"  최대: μ_adh={smart_fmt(peak_mu)} @ v={v_array[peak_idx]:.4f} m/s\n")

            # Total friction
            if self.mu_visc_results is not None and 'mu' in self.mu_visc_results:
                mu_visc = self.mu_visc_results['mu']
                if len(mu_visc) == len(mu_adh):
                    mu_total = mu_visc + mu_adh
                    self.adh_result_text.insert(tk.END, f"\n[μ_total = μ_visc + μ_adh]\n")
                    total_peak_idx = np.argmax(mu_total)
                    self.adh_result_text.insert(tk.END, f"  범위: {smart_fmt(np.min(mu_total))} ~ {smart_fmt(np.max(mu_total))}\n")
                    self.adh_result_text.insert(tk.END, f"  최대: μ_total={smart_fmt(mu_total[total_peak_idx])} @ v={v_array[total_peak_idx]:.4f} m/s\n")

            self.adh_result_text.insert(tk.END, f"\n[속도별 μ_adh]\n")
            step = max(1, n_v // 8)
            for i in range(0, n_v, step):
                self.adh_result_text.insert(tk.END,
                    f"  v={v_array[i]:.2e}: τ_f={tau_f[i]/1e6:.4f}MPa, A/A0={A_ratio[i]:.4f}, μ_adh={smart_fmt(mu_adh[i])}\n")

            self.adh_progress_var.set(100)
            if self._adh_fitting_completed:
                self.status_var.set(f"μ_adh 계산 완료 (피팅 확정 — T={T_calc_C:.1f}°C)")
            else:
                self.status_var.set("μ_adh 계산 완료")
            self.adh_calc_button.config(state='normal')

            if self._adh_fitting_completed:
                self._show_status(
                    f"μ_adh 계산 완료 (피팅 확정 파라미터, T={T_calc_C:.1f}°C)\n"
                    f"범위: {smart_fmt(mu_min)} ~ {smart_fmt(mu_max)}\n"
                    f"최대: μ_adh={smart_fmt(peak_mu)} @ v={v_array[peak_idx]:.4f} m/s", 'success')
            else:
                self._show_status(
                    f"μ_adh 계산 완료\n"
                    f"범위: {smart_fmt(mu_min)} ~ {smart_fmt(mu_max)}\n"
                    f"최대: μ_adh={smart_fmt(peak_mu)} @ v={v_array[peak_idx]:.4f} m/s", 'success')

            # Register graph data
            self._register_graph_data(
                "Adhesion_mu_adh_vs_v", v_array, mu_adh,
                "v(m/s)\tmu_adh", "Adhesion friction coefficient vs velocity")
            self._register_graph_data(
                "Adhesion_tau_f_vs_v", v_array, tau_f / 1e6,
                "v(m/s)\ttau_f(MPa)", "Adhesion shear stress vs velocity")

        except ValueError as e:
            self.adh_calc_button.config(state='normal')
            self._show_status(f"입력값 오류: {str(e)}\n파라미터 값을 확인하세요.", 'warning')
        except Exception as e:
            self.adh_calc_button.config(state='normal')
            messagebox.showerror("오류", f"μ_adh 계산 실패:\n{str(e)}")
            import traceback
            traceback.print_exc()

    def _update_mu_adh_plots(self):
        """Update μ_adh plots with calculated results.

        Layout:
        - Plot 1 (221): τ_f (shear stress) + A/A0 dual y-axis vs velocity
        - Plot 2 (222): μ_adh vs velocity
        - Plot 3 (223): μ_total = μ_visc + μ_adh vs velocity
        - Plot 4 (224): aT comparison (master curve aT vs adhesion Arrhenius aT')
        """
        if self.mu_adh_results is None:
            return

        try:
            v = self.mu_adh_results['v']
            mu_adh = self.mu_adh_results['mu_adh']
            tau_f = self.mu_adh_results['tau_f']
            A_ratio = self.mu_adh_results['A_ratio']

            # Clear all subplots
            self.ax_adh_tau.clear()
            # Remove old twin axes if any
            if hasattr(self, '_ax_adh_tau_twin') and self._ax_adh_tau_twin is not None:
                self._ax_adh_tau_twin.remove()
                self._ax_adh_tau_twin = None
            self.ax_adh_mu.clear()
            self.ax_adh_total.clear()
            self.ax_adh_area.clear()

            def smart_fmt(val):
                if abs(val) < 0.001 and val != 0:
                    return f'{val:.2e}'
                return f'{val:.4f}'

            # ── Plot 1: τ_f (shear stress) + A/A0 dual y-axis vs velocity ──
            use_flash = self.mu_adh_results.get('use_flash', False)
            tau_f_cold_plot = self.mu_adh_results.get('tau_f_cold')

            # If flash active, show cold (dashed) and hot (solid) τ_f
            if use_flash and tau_f_cold_plot is not None:
                self.ax_adh_tau.semilogx(v, tau_f_cold_plot / 1e6, 'b--', linewidth=1.5,
                                         alpha=0.6, label='τ_f (Cold)')
                line_tau = self.ax_adh_tau.semilogx(v, tau_f / 1e6, 'r-', linewidth=2,
                                                     marker='o', markersize=3, label='τ_f (Hot, stretched)')
            else:
                line_tau = self.ax_adh_tau.semilogx(v, tau_f / 1e6, 'r-', linewidth=2,
                                                     marker='o', markersize=3, label='τ_f')
            peak_tau_idx = np.argmax(tau_f)
            self.ax_adh_tau.plot(v[peak_tau_idx], tau_f[peak_tau_idx] / 1e6, 'r*', markersize=12,
                                label=f'최대: {tau_f[peak_tau_idx]/1e6:.3f} MPa')
            title_suffix = ' (Flash 보정)' if use_flash else ''
            self.ax_adh_tau.set_title(f'점착 전단 응력 τ_f(v) + A/A0{title_suffix}', fontweight='bold', fontsize=11)
            self.ax_adh_tau.set_xlabel('속도 v (m/s)', fontsize=11)
            self.ax_adh_tau.set_ylabel('τ_f (MPa)', fontsize=11, color='r')
            self.ax_adh_tau.tick_params(axis='y', labelcolor='r')

            # A/A0 on secondary y-axis (same plot)
            self._ax_adh_tau_twin = self.ax_adh_tau.twinx()
            line_area = self._ax_adh_tau_twin.semilogx(v, A_ratio, 'b--', linewidth=1.5,
                                                        marker='s', markersize=2, alpha=0.7,
                                                        label='A/A0')
            self._ax_adh_tau_twin.set_ylabel('A/A0 (실접촉 면적비)', fontsize=10, color='b')
            self._ax_adh_tau_twin.tick_params(axis='y', labelcolor='b')
            y_max_area = np.max(A_ratio) * 1.3
            if not np.isfinite(y_max_area) or y_max_area <= 0:
                y_max_area = 0.1
            self._ax_adh_tau_twin.set_ylim(0, y_max_area)

            # Combined legend
            lines = line_tau + line_area
            labels = [l.get_label() for l in lines]
            self.ax_adh_tau.legend(lines, labels, loc='best', fontsize=7)
            self.ax_adh_tau.grid(True, alpha=0.3)

            # ── Plot 2: μ_adh vs velocity ──
            self.ax_adh_mu.semilogx(v, mu_adh, 'g-', linewidth=2.5, marker='o', markersize=4)
            peak_mu_idx = np.argmax(mu_adh)
            self.ax_adh_mu.plot(v[peak_mu_idx], mu_adh[peak_mu_idx], 'r*', markersize=15,
                                label=f'최대: μ={smart_fmt(mu_adh[peak_mu_idx])} @ v={v[peak_mu_idx]:.4f}')
            self.ax_adh_mu.set_title('μ_adh(v) 곡선', fontweight='bold', fontsize=11)
            self.ax_adh_mu.set_xlabel('속도 v (m/s)', fontsize=11)
            self.ax_adh_mu.set_ylabel('마찰 계수 μ_adh', fontsize=11)
            self.ax_adh_mu.legend(loc='best', fontsize=8)
            self.ax_adh_mu.grid(True, alpha=0.3)

            # ── Plot 3: μ_total = μ_visc + μ_adh ──
            has_mu_visc = (self.mu_visc_results is not None and
                           'mu' in self.mu_visc_results and
                           len(self.mu_visc_results['mu']) == len(mu_adh))

            if has_mu_visc and self.adh_show_total_var.get():
                mu_visc = self.mu_visc_results['mu']
                mu_total = mu_visc + mu_adh

                self.ax_adh_total.semilogx(v, mu_total, 'k-', linewidth=2.5,
                                            label='μ_total', zorder=10)
                self.ax_adh_total.semilogx(v, mu_visc, 'b--', linewidth=1.5,
                                            alpha=0.7, label='μ_visc')
                self.ax_adh_total.semilogx(v, mu_adh, 'g--', linewidth=1.5,
                                            alpha=0.7, label='μ_adh')

                # Mark peak total
                total_peak_idx = np.argmax(mu_total)
                self.ax_adh_total.plot(v[total_peak_idx], mu_total[total_peak_idx], 'r*',
                                        markersize=15,
                                        label=f'최대: μ={smart_fmt(mu_total[total_peak_idx])}')

                # Store total results
                self.mu_adh_results['mu_total'] = mu_total

                self._register_graph_data(
                    "Total_mu_total_vs_v", v, mu_total,
                    "v(m/s)\tmu_total", "Total friction (visc + adh) vs velocity")
            else:
                self.ax_adh_total.semilogx(v, mu_adh, 'g-', linewidth=2, label='μ_adh')
                self.ax_adh_total.text(0.5, 0.95, 'μ_visc 결과 없음 - μ_adh만 표시',
                                        ha='center', va='top', fontsize=9, color='#64748B',
                                        transform=self.ax_adh_total.transAxes)

            # Overlay measured μ_dry data points (if available)
            v_meas, mu_dry_meas = self._get_measured_mu_dry_data()
            if v_meas is not None and len(v_meas) > 0:
                self.ax_adh_total.plot(v_meas, mu_dry_meas, 'rs', markersize=8,
                                        markeredgecolor='darkred', markeredgewidth=1.5,
                                        zorder=20, label=f'실측 μ_dry ({len(v_meas)}점)')

            self.ax_adh_total.set_title('μ_total(cold) = μ_visc + μ_adh', fontweight='bold', fontsize=11)
            self.ax_adh_total.set_xlabel('속도 v (m/s)', fontsize=11)
            self.ax_adh_total.set_ylabel('마찰 계수 μ', fontsize=11)
            self.ax_adh_total.legend(loc='best', fontsize=8)
            self.ax_adh_total.grid(True, alpha=0.3)

            # ── Plot 4: aT comparison (master curve aT vs adhesion Arrhenius aT') ──
            params = self.mu_adh_results.get('params', {})
            epsilon = params.get('epsilon', 0.97)
            T_ref_K = params.get('T_ref', 293.15)
            T_calc_K = params.get('T', 293.15)
            T_calc_C = T_calc_K - 273.15
            k_B = 8.6173e-5

            # Plot master curve aT if data available
            has_mc_aT = (hasattr(self, 'persson_aT_data') and self.persson_aT_data is not None)
            if has_mc_aT:
                mc_T = self.persson_aT_data['T']
                mc_log_aT = self.persson_aT_data['log_aT']
                T_ref_mc_C = self.persson_aT_data.get('T_ref', 20.0)
                self.ax_adh_area.plot(mc_T, mc_log_aT, 'b-', linewidth=2,
                                      marker='o', markersize=3,
                                      label=f'마스터 커브 aT (Tref={T_ref_mc_C:.0f}°C)')

            # Plot adhesion Arrhenius aT' over temperature range
            T_ref_C = T_ref_K - 273.15
            if has_mc_aT:
                T_range_C = np.linspace(min(mc_T.min(), T_ref_C - 50),
                                         max(mc_T.max(), T_ref_C + 50), 100)
            else:
                T_range_C = np.linspace(T_ref_C - 80, T_ref_C + 80, 100)
            T_range_K = T_range_C + 273.15
            aT_adh = np.exp((epsilon / k_B) * (1.0 / T_range_K - 1.0 / T_ref_K))
            log_aT_adh = np.log10(aT_adh)
            self.ax_adh_area.plot(T_range_C, log_aT_adh, 'r--', linewidth=2,
                                  label=f'전단응력 aT\' (Arrhenius, ε={epsilon:.2f}eV)')

            # Mark current calculation temperature
            aT_prime_current = self.mu_adh_results.get('aT_prime_cold', self.mu_adh_results.get('aT_prime', 1.0))
            if np.ndim(aT_prime_current) > 0:
                aT_prime_current = float(aT_prime_current[0]) if len(aT_prime_current) > 0 else 1.0
            log_aT_current = np.log10(aT_prime_current) if aT_prime_current > 0 else 0
            self.ax_adh_area.plot(T_calc_C, log_aT_current, 'r*', markersize=15, zorder=10,
                                  label=f'T_base={T_calc_C:.1f}°C (aT\'={aT_prime_current:.2e})')

            # If flash active, show T_hot range on the aT curve
            if self.mu_adh_results.get('use_flash', False):
                flash_res = self.mu_visc_results.get('flash_results', {}) if self.mu_visc_results else {}
                T_hot_arr_C_plot = np.array(flash_res.get('T_hot', []))
                if len(T_hot_arr_C_plot) > 0:
                    T_hot_max_C = np.max(T_hot_arr_C_plot)
                    T_hot_max_K = T_hot_max_C + 273.15
                    aT_at_max = np.exp((epsilon / k_B) * (1.0 / T_hot_max_K - 1.0 / T_ref_K))
                    log_aT_max = np.log10(aT_at_max) if aT_at_max > 0 else 0
                    self.ax_adh_area.plot(T_hot_max_C, log_aT_max, 'r^', markersize=12, zorder=10,
                                          label=f'T_hot_max={T_hot_max_C:.1f}°C')
                    # Shade the flash temperature range
                    self.ax_adh_area.axvspan(T_calc_C, T_hot_max_C, alpha=0.1, color='red',
                                              label='Flash T 범위')

            # Mark master curve aT at current temperature if available
            if has_mc_aT and hasattr(self, 'persson_aT_interp') and self.persson_aT_interp is not None:
                try:
                    mc_log_aT_at_T = float(self.persson_aT_interp(T_calc_C))
                    self.ax_adh_area.plot(T_calc_C, mc_log_aT_at_T, 'b*', markersize=15, zorder=10,
                                          label=f'마스터 aT={10**mc_log_aT_at_T:.2e}')
                except Exception:
                    pass

            self.ax_adh_area.set_title('이동 인자 aT 비교', fontweight='bold', fontsize=11)
            self.ax_adh_area.set_xlabel('온도 T (°C)', fontsize=11)
            self.ax_adh_area.set_ylabel('log₁₀(aT)', fontsize=11)
            self.ax_adh_area.legend(loc='best', fontsize=7)
            self.ax_adh_area.grid(True, alpha=0.3)
            self.ax_adh_area.axhline(y=0, color='gray', linestyle=':', alpha=0.5)

            self.fig_mu_adh.subplots_adjust(left=0.10, right=0.90, top=0.96, bottom=0.08,
                                             hspace=0.50, wspace=0.45)
            self.canvas_mu_adh.draw()

        except Exception as e:
            print(f"μ_adh plot update error: {e}")
            import traceback
            traceback.print_exc()

    def _export_mu_adh_csv(self):
        """Export μ_adh calculation results to CSV (comma-separated, with headers)."""
        if self.mu_adh_results is None:
            self._show_status("μ_adh 결과가 없습니다. 먼저 계산을 실행하세요.", 'warning')
            return

        mc_prefix = self._get_mc_prefix()
        default_fn = f"{mc_prefix}_mu_adh_results.csv" if mc_prefix else "mu_adh_results.csv"

        filepath = filedialog.asksaveasfilename(
            title="μ_adh 데이터 내보내기",
            defaultextension=".csv",
            filetypes=[("CSV", "*.csv"), ("텍스트", "*.txt")],
            initialfile=default_fn
        )
        if not filepath:
            return

        try:
            from datetime import datetime
            v = self.mu_adh_results['v']
            mu_adh = self.mu_adh_results['mu_adh']
            tau_f = self.mu_adh_results['tau_f']
            A_ratio = self.mu_adh_results['A_ratio']
            v_eff = self.mu_adh_results['v_eff']
            params = self.mu_adh_results['params']

            lines = [
                f"# 생성일시,{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
                f"# 마스터커브,{mc_prefix if mc_prefix else 'N/A'}",
                f"# tau_f0 (MPa),{params['tau_f0']/1e6:.2f}",
                f"# v0_star (m/s),{params['v0_star']:.4f}",
                f"# c,{params['c']:.4f}",
                f"# epsilon (eV),{params['epsilon']:.4f}",
                f"# T (K),{params['T']:.2f}",
                f"# T_ref (K),{params['T_ref']:.2f}",
                f"# p0 (MPa),{params['p0']/1e6:.3f}",
                f"# aT_prime,{self.mu_adh_results['aT_prime']:.6e}",
                f"# A/A0 source,{params.get('area_source', 'N/A')}",
                "#",
                "log10(v),velocity [m/s],v_eff [m/s],tau_f [MPa],A/A0,mu_adh"
            ]
            for i in range(len(v)):
                lines.append(f"{np.log10(v[i]):.6f},{v[i]:.6e},{v_eff[i]:.6e},"
                             f"{tau_f[i]/1e6:.6f},{A_ratio[i]:.6f},{mu_adh[i]:.6f}")

            with open(filepath, 'w', encoding='utf-8-sig') as f:
                f.write("\n".join(lines))

            self._show_status(f"μ_adh 데이터 저장 완료: {filepath}", 'success')
        except Exception as e:
            messagebox.showerror("오류", f"CSV 저장 실패:\n{str(e)}")

    def _export_mu_total_csv(self):
        """Export μ_total (μ_visc + μ_adh) results to CSV (comma-separated, with headers)."""
        if self.mu_adh_results is None:
            self._show_status("μ_adh 결과가 없습니다. 먼저 계산을 실행하세요.", 'warning')
            return

        mc_prefix = self._get_mc_prefix()
        default_fn = f"{mc_prefix}_mu_total_results.csv" if mc_prefix else "mu_total_results.csv"

        filepath = filedialog.asksaveasfilename(
            title="μ_total 데이터 내보내기",
            defaultextension=".csv",
            filetypes=[("CSV", "*.csv"), ("텍스트", "*.txt")],
            initialfile=default_fn
        )
        if not filepath:
            return

        try:
            from datetime import datetime
            v = self.mu_adh_results['v']
            mu_adh = self.mu_adh_results['mu_adh']

            has_visc = (self.mu_visc_results is not None and
                        'mu' in self.mu_visc_results and
                        len(self.mu_visc_results['mu']) == len(mu_adh))

            mu_visc = self.mu_visc_results['mu'] if has_visc else np.zeros_like(mu_adh)
            mu_total = mu_visc + mu_adh

            # Check for flash-corrected mu_hot
            has_flash = (has_visc and
                         self.mu_visc_results.get('use_flash', False) and
                         self.mu_visc_results.get('mu_hot') is not None and
                         len(self.mu_visc_results['mu_hot']) == len(mu_adh))
            mu_hot = self.mu_visc_results.get('mu_hot') if has_flash else None
            mu_total_hot = (mu_hot + mu_adh) if mu_hot is not None else None

            lines = [
                f"# 생성일시,{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
                f"# 마스터커브,{mc_prefix if mc_prefix else 'N/A'}",
                f"# mu_total = mu_visc + mu_adh",
                "#",
            ]

            if mu_total_hot is not None:
                lines.append("log10(v),velocity [m/s],mu_visc,mu_adh,mu_total,"
                             "mu_visc_hot,mu_total_hot")
                for i in range(len(v)):
                    lines.append(f"{np.log10(v[i]):.6f},{v[i]:.6e},"
                                 f"{mu_visc[i]:.6f},{mu_adh[i]:.6f},{mu_total[i]:.6f},"
                                 f"{mu_hot[i]:.6f},{mu_total_hot[i]:.6f}")
            else:
                lines.append("log10(v),velocity [m/s],mu_visc,mu_adh,mu_total")
                for i in range(len(v)):
                    lines.append(f"{np.log10(v[i]):.6f},{v[i]:.6e},"
                                 f"{mu_visc[i]:.6f},{mu_adh[i]:.6f},{mu_total[i]:.6f}")

            with open(filepath, 'w', encoding='utf-8-sig') as f:
                f.write("\n".join(lines))

            self._show_status(f"μ_total 데이터 저장 완료: {filepath}", 'success')
        except Exception as e:
            messagebox.showerror("오류", f"CSV 저장 실패:\n{str(e)}")

    # ── Measured μ_dry data management ──

    def _add_measured_mu_dry(self):
        """Add a single measured μ_dry data point to the table.

        Velocity is expected in log10 scale (e.g., -3 means v = 0.001 m/s).
        """
        try:
            v_str = self.meas_v_entry_var.get().strip()
            mu_str = self.meas_mu_entry_var.get().strip()
            if not v_str or not mu_str:
                self._show_status("log₁₀(v)와 μ_dry 값을 모두 입력하세요.", 'warning')
                return
            log_v_val = float(v_str)
            mu_val = float(mu_str)
            self.meas_mu_tree.insert('', tk.END, values=(f"{log_v_val:.4f}", f"{mu_val:.6f}"))
            self.meas_v_entry_var.set("")
            self.meas_mu_entry_var.set("")
        except ValueError:
            self._show_status("숫자 형식 오류. 올바른 값을 입력하세요.", 'warning')

    def _delete_selected_measured(self):
        """Delete selected rows from measured μ_dry table."""
        selected = self.meas_mu_tree.selection()
        if not selected:
            self._show_status("삭제할 항목을 선택하세요.", 'warning')
            return
        for item in selected:
            self.meas_mu_tree.delete(item)

    def _clear_measured_mu_dry(self):
        """Clear all measured μ_dry data."""
        for item in self.meas_mu_tree.get_children():
            self.meas_mu_tree.delete(item)
        self._show_status("실측 데이터가 모두 삭제되었습니다.", 'info')

    def _load_measured_mu_dry_csv(self):
        """Load measured μ_dry data from CSV/TXT file.

        Expected format: two columns (log10(velocity), mu_dry) separated by tab, comma, or space.
        Velocity column is in log10 scale (e.g., -3 means v = 0.001 m/s).
        Lines starting with '#' are comments.
        """
        filepath = filedialog.askopenfilename(
            title="실측 μ_dry 데이터 파일 선택",
            filetypes=[("CSV/텍스트", "*.csv *.txt *.dat"), ("모든 파일", "*.*")]
        )
        if not filepath:
            return
        try:
            count = 0
            with open(filepath, 'r') as f:
                for line in f:
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue
                    # Try tab, comma, then whitespace
                    for sep in ['\t', ',', None]:
                        parts = line.split(sep)
                        if len(parts) >= 2:
                            try:
                                log_v_val = float(parts[0].strip())
                                mu_val = float(parts[1].strip())
                                self.meas_mu_tree.insert('', tk.END,
                                                         values=(f"{log_v_val:.4f}", f"{mu_val:.6f}"))
                                count += 1
                                break
                            except ValueError:
                                continue
            self._show_status(f"실측 데이터 {count}개 로드 완료: {os.path.basename(filepath)}", 'success')
        except Exception as e:
            messagebox.showerror("오류", f"파일 로드 실패:\n{str(e)}")

    def _export_measured_mu_dry_csv(self):
        """Export measured μ_dry data to CSV file."""
        items = self.meas_mu_tree.get_children()
        if not items:
            self._show_status("내보낼 실측 데이터가 없습니다.", 'warning')
            return
        filepath = filedialog.asksaveasfilename(
            title="실측 μ_dry 데이터 저장",
            defaultextension=".csv",
            filetypes=[("CSV", "*.csv"), ("텍스트", "*.txt")]
        )
        if not filepath:
            return
        try:
            with open(filepath, 'w') as f:
                f.write("# log10(v_m/s),mu_dry\n")
                for item in items:
                    vals = self.meas_mu_tree.item(item)['values']
                    f.write(f"{vals[0]},{vals[1]}\n")
            self._show_status(f"실측 데이터 {len(items)}개 저장 완료: {os.path.basename(filepath)}", 'success')
        except Exception as e:
            messagebox.showerror("오류", f"저장 실패:\n{str(e)}")

    def _refresh_preset_mu_dry_list(self):
        """Refresh the preset μ_dry list in the combobox."""
        try:
            preset_dir = self._get_preset_data_dir('mu_dry')
            files = [f for f in os.listdir(preset_dir) if f.endswith(('.txt', '.csv'))]
            if files:
                self.preset_mu_dry_combo['values'] = files
            else:
                self.preset_mu_dry_combo['values'] = ['(데이터 없음)']
        except Exception as e:
            print(f"[내장 μ_dry] 목록 로드 오류: {e}")
            self.preset_mu_dry_combo['values'] = ['(오류)']

    def _load_preset_mu_dry(self):
        """Load a preset μ_dry file into the treeview table."""
        selected = self.preset_mu_dry_var.get()
        if not selected or selected.startswith('('):
            self._show_status("내장 μ_dry 프리셋을 선택하세요.", 'warning')
            return

        try:
            preset_dir = self._get_preset_data_dir('mu_dry')
            filepath = os.path.join(preset_dir, selected)

            # Clear existing data
            for item in self.meas_mu_tree.get_children():
                self.meas_mu_tree.delete(item)

            # Load data (multi-encoding)
            count = 0
            data_loaded = False
            for enc in ['utf-8', 'cp949', 'euc-kr', 'latin-1']:
                try:
                    with open(filepath, 'r', encoding=enc) as f:
                        for line in f:
                            line = line.strip()
                            if not line or line.startswith('#'):
                                continue
                            for sep in ['\t', ',', None]:
                                parts = line.split(sep)
                                if len(parts) >= 2:
                                    try:
                                        log_v_val = float(parts[0].strip())
                                        mu_val = float(parts[1].strip())
                                        self.meas_mu_tree.insert('', tk.END,
                                                                 values=(f"{log_v_val:.4f}", f"{mu_val:.6f}"))
                                        count += 1
                                        break
                                    except ValueError:
                                        continue
                    data_loaded = True
                    break
                except UnicodeDecodeError:
                    continue

            if not data_loaded:
                raise ValueError("파일 인코딩을 인식할 수 없습니다.")

            self._show_status(f"내장 μ_dry 프리셋 로드 완료: {selected} ({count}개)", 'success')

        except Exception as e:
            messagebox.showerror("오류", f"내장 μ_dry 로드 실패:\n{str(e)}")

    def _add_preset_mu_dry(self):
        """Save current treeview μ_dry data as a preset."""
        items = self.meas_mu_tree.get_children()
        if not items:
            self._show_status("저장할 실측 μ_dry 데이터가 없습니다.\n먼저 데이터를 입력하세요.", 'warning')
            return

        from tkinter import simpledialog
        name = simpledialog.askstring("내장 μ_dry 프리셋 추가", "저장할 이름을 입력하세요:")
        if not name:
            return

        if not name.endswith('.txt'):
            name += '.txt'

        try:
            preset_dir = self._get_preset_data_dir('mu_dry')
            filepath = os.path.join(preset_dir, name)

            with open(filepath, 'w', encoding='utf-8') as f:
                f.write("# 내장 μ_dry 프리셋 데이터\n")
                f.write("# log10(v_m/s)\tmu_dry\n")
                for item in items:
                    vals = self.meas_mu_tree.item(item)['values']
                    f.write(f"{vals[0]}\t{vals[1]}\n")

            self._refresh_preset_mu_dry_list()
            self.preset_mu_dry_var.set(name)
            self._show_status(f"프리셋 저장 완료: {name} ({len(items)}개)", 'success')

        except Exception as e:
            messagebox.showerror("오류", f"프리셋 저장 실패:\n{str(e)}")

    def _delete_preset_mu_dry(self):
        """Delete selected preset μ_dry file."""
        selected = self.preset_mu_dry_var.get()
        if not selected or selected.startswith('('):
            self._show_status("삭제할 내장 μ_dry 프리셋을 선택하세요.", 'warning')
            return

        if not messagebox.askyesno("확인", f"'{selected}' 프리셋을 삭제하시겠습니까?"):
            return

        try:
            preset_dir = self._get_preset_data_dir('mu_dry')
            filepath = os.path.join(preset_dir, selected)
            os.remove(filepath)
            self._refresh_preset_mu_dry_list()
            self.preset_mu_dry_var.set("(선택...)")
            self._show_status(f"프리셋 삭제 완료: {selected}", 'success')
        except Exception as e:
            messagebox.showerror("오류", f"프리셋 삭제 실패:\n{str(e)}")

    def _get_measured_mu_dry_data(self):
        """Get measured μ_dry data as numpy arrays.

        The treeview stores log10(v). This function converts to linear velocity.

        Returns:
            tuple: (v_measured, mu_dry_measured) or (None, None) if no data.
                   v_measured is in linear scale (m/s), converted from log10.
        """
        items = self.meas_mu_tree.get_children()
        if not items:
            return None, None
        v_list = []
        mu_list = []
        for item in items:
            vals = self.meas_mu_tree.item(item, 'values')
            log_v = float(vals[0])
            v_list.append(10.0 ** log_v)  # Convert from log10 to linear
            mu_list.append(float(vals[1]))
        # Sort by velocity
        v_arr = np.array(v_list)
        mu_arr = np.array(mu_list)
        sort_idx = np.argsort(v_arr)
        return v_arr[sort_idx], mu_arr[sort_idx]

    # ── Auto-fitting ──

    def _run_auto_fit_mu_dry(self):
        """Auto-fit adhesion parameters (τ_f0, v₀*, c) to match measured μ_dry.

        Uses multi-restart differential evolution (n_restarts × 4 strategies)
        followed by Nelder-Mead local refinement to maximize R².

        Minimizes: sum[(μ_dry_model(v_i) - μ_dry_measured(v_i))²]
        where μ_dry_model = μ_visc(v_i) + μ_adh(v_i; τ_f0, v₀*, c)
        """
        from scipy.optimize import differential_evolution, minimize
        from scipy.interpolate import interp1d

        try:
            self.fit_button.config(state='disabled')
            self.fit_status_var.set("피팅 실행 중...")
            self.root.update()

            # ── Validate prerequisites ──
            v_meas, mu_dry_meas = self._get_measured_mu_dry_data()
            if v_meas is None or len(v_meas) < 2:
                self._show_status("실측 데이터가 최소 2개 이상 필요합니다.", 'warning')
                self.fit_button.config(state='normal')
                self.fit_status_var.set("실측 데이터 부족")
                return

            # Need mu_visc results for the model velocity array and mu_visc values
            if self.mu_visc_results is None or 'mu' not in self.mu_visc_results:
                self._show_status("μ_visc 결과가 필요합니다. 먼저 μ_visc 탭에서 계산하세요.", 'warning')
                self.fit_button.config(state='normal')
                self.fit_status_var.set("μ_visc 결과 필요")
                return

            v_model = self.mu_visc_results['v']
            # 항상 cold mu_visc 사용: 실측 mu_dry는 기본 온도(cold) 데이터이므로
            # cold mu_visc + cold mu_adh = mu_dry 로 피팅해야 함.
            # Hot 효과는 Cold & Hot Branch 탭에서 별도 적용.
            mu_visc_model = self.mu_visc_results['mu']

            # Need A/A0 data
            area_source = self.adh_area_source_var.get()
            if area_source == "from_mu_visc":
                if 'P_qmax' not in self.mu_visc_results:
                    self._show_status("A/A0 데이터 없음. μ_visc 결과에 P_qmax가 필요합니다.", 'warning')
                    self.fit_button.config(state='normal')
                    return
                A_ratio_model = self.mu_visc_results['P_qmax']
            else:
                fixed_area = float(self.adh_fixed_area_var.get())
                A_ratio_model = np.full(len(v_model), np.clip(fixed_area, 0.0, 1.0))

            # ── Auto-sync T_ref from Tab 2 aT data ──
            if hasattr(self, 'persson_aT_data') and self.persson_aT_data is not None:
                T_ref_C = self.persson_aT_data.get('T_ref', None)
                if T_ref_C is not None:
                    T_ref_K = T_ref_C + 273.15
                    self.adh_T_ref_var.set(f"{T_ref_K:.2f}")

            # ── Auto-sync p0 from σ₀ if empty ──
            p0_str = self.adh_p0_var.get().strip()
            if not p0_str:
                if hasattr(self, 'sigma_0_var'):
                    p0_str = self.sigma_0_var.get()
                    self.adh_p0_var.set(p0_str)

            # Read fixed parameters (ε, T_ref, T, p0)
            epsilon = float(self.adh_epsilon_var.get())
            T_ref = float(self.adh_T_ref_var.get())
            k_B = 8.6173e-5
            T_calc_C = float(self.adh_calc_temp_var.get())
            T = T_calc_C + 273.15
            p0 = float(p0_str) * 1e6  # MPa → Pa

            # Arrhenius shift factor — 항상 cold (기본 온도) 사용
            # mu_adh 탭의 피팅은 cold 조건에서 수행.
            # Flash temperature 효과는 Cold & Hot Branch 탭에서 적용.
            aT_prime_cold = np.exp((epsilon / k_B) * (1.0 / T - 1.0 / T_ref))
            aT_prime = aT_prime_cold  # always cold (scalar)

            # Create interpolators for mu_visc and A_ratio at measured velocities
            log_v_model = np.log10(v_model)
            mu_visc_interp = interp1d(log_v_model, mu_visc_model,
                                      kind='linear', fill_value='extrapolate')
            A_ratio_interp = interp1d(log_v_model, A_ratio_model,
                                      kind='linear', fill_value='extrapolate')

            log_v_meas = np.log10(v_meas)
            mu_visc_at_meas = mu_visc_interp(log_v_meas)
            A_ratio_at_meas = A_ratio_interp(log_v_meas)

            # ── Read bounds ──
            tau_min = float(self.fit_tau_min_var.get()) * 1e6   # MPa → Pa
            tau_max = float(self.fit_tau_max_var.get()) * 1e6
            v0_min = float(self.fit_v0_min_var.get())
            v0_max = float(self.fit_v0_max_var.get())
            c_min = float(self.fit_c_min_var.get())
            c_max = float(self.fit_c_max_var.get())

            bounds = [(tau_min, tau_max), (v0_min, v0_max), (c_min, c_max)]

            # ── Objective function ──
            def objective(params):
                tau_f0, v0_star, c = params
                v_eff = v_meas * aT_prime
                log_ratio = np.log10(v_eff / v0_star)
                tau_f = tau_f0 * np.exp(-c * log_ratio**2)
                mu_adh = (tau_f / p0) * A_ratio_at_meas
                mu_dry_model = mu_visc_at_meas + mu_adh
                residual = mu_dry_model - mu_dry_meas
                return np.sum(residual**2)

            # ── Run multi-restart differential evolution for best R² ──
            best_result = None
            best_cost = np.inf
            try:
                n_restarts = max(1, int(self.fit_de_count_var.get()))
            except (ValueError, AttributeError):
                n_restarts = 3
            strategies = ['best1bin', 'best2bin', 'rand1bin', 'randtobest1bin']
            total_trials = n_restarts * len(strategies)
            trial_count = 0

            for i_restart in range(n_restarts):
                for strategy in strategies:
                    trial_count += 1
                    self.fit_status_var.set(
                        f"DE 탐색 중... ({trial_count}/{total_trials})"
                        f"{f'  현재 최적: {best_cost:.2e}' if best_cost < np.inf else ''}")
                    self.root.update()
                    try:
                        res = differential_evolution(
                            objective, bounds,
                            seed=i_restart * 7 + 3,
                            strategy=strategy,
                            maxiter=2000,
                            tol=1e-12,
                            popsize=30,
                            mutation=(0.5, 1.5),
                            recombination=0.9,
                            init='sobol' if i_restart % 2 == 0 else 'latinhypercube',
                            polish=True,
                            disp=False)
                        if res.fun < best_cost:
                            best_cost = res.fun
                            best_result = res
                    except Exception:
                        continue

            self.fit_status_var.set("로컬 최적화 (Nelder-Mead) 실행 중...")
            self.root.update()
            # Also try Nelder-Mead from multiple initial guesses
            tau_mid = (tau_min + tau_max) / 2
            v0_mid = np.sqrt(v0_min * v0_max)
            c_mid = (c_min + c_max) / 2
            initial_guesses = [
                [tau_mid, v0_mid, c_mid],
                [tau_min, v0_min, c_min],
                [tau_max, v0_max, c_max],
                [tau_mid, v0_min, c_max],
                [tau_max, v0_min, c_min],
            ]
            if best_result is not None:
                initial_guesses.append(list(best_result.x))

            for x0 in initial_guesses:
                try:
                    res_nm = minimize(objective, x0, method='Nelder-Mead',
                                     options={'maxiter': 10000, 'xatol': 1e-12,
                                              'fatol': 1e-12, 'adaptive': True})
                    # Check bounds
                    t, v, cc = res_nm.x
                    if (tau_min <= t <= tau_max and v0_min <= v <= v0_max
                            and c_min <= cc <= c_max and res_nm.fun < best_cost):
                        best_cost = res_nm.fun
                        best_result = res_nm
                except Exception:
                    continue

            if best_result is None:
                self._show_status("피팅 실패: 유효한 결과를 찾지 못했습니다.", 'warning')
                self.fit_status_var.set("피팅 실패")
                self.fit_button.config(state='normal')
                return

            result = best_result
            opt_tau_f0, opt_v0_star, opt_c = result.x

            # Calculate fitted mu_dry at measured points
            v_eff_meas = v_meas * aT_prime
            log_ratio_fit = np.log10(v_eff_meas / opt_v0_star)
            tau_f_fit = opt_tau_f0 * np.exp(-opt_c * log_ratio_fit**2)
            mu_adh_fit = (tau_f_fit / p0) * A_ratio_at_meas
            mu_dry_fit = mu_visc_at_meas + mu_adh_fit

            # R² calculation
            ss_res = np.sum((mu_dry_meas - mu_dry_fit)**2)
            ss_tot = np.sum((mu_dry_meas - np.mean(mu_dry_meas))**2)
            r_squared = 1.0 - ss_res / ss_tot if ss_tot > 0 else 0.0

            # RMSE
            rmse = np.sqrt(np.mean((mu_dry_meas - mu_dry_fit)**2))

            # ── Store fit results ──
            self._fit_results = {
                'tau_f0': opt_tau_f0,       # Pa
                'v0_star': opt_v0_star,     # m/s
                'c': opt_c,
                'r_squared': r_squared,
                'rmse': rmse,
                'v_meas': v_meas,
                'mu_dry_meas': mu_dry_meas,
                'mu_dry_fit': mu_dry_fit,
                'success': result.success,
                'message': result.message,
            }

            # ── Display fit results ──
            self.fit_result_text.delete(1.0, tk.END)
            self.fit_result_text.insert(tk.END, f"=== 자동 피팅 결과 (DE + Nelder-Mead, Cold) ===\n")
            self.fit_result_text.insert(tk.END, f"  탐색: DE {total_trials}회 + Nelder-Mead {len(initial_guesses)}회\n")
            self.fit_result_text.insert(tk.END, f"  τ_f0  = {opt_tau_f0/1e6:.4f} MPa\n")
            self.fit_result_text.insert(tk.END, f"  v₀*   = {opt_v0_star:.6e} m/s\n")
            self.fit_result_text.insert(tk.END, f"  c     = {opt_c:.6f}\n")
            self.fit_result_text.insert(tk.END, f"  R²    = {r_squared:.6f}\n")
            self.fit_result_text.insert(tk.END, f"  RMSE  = {rmse:.6e}\n")
            self.fit_result_text.insert(tk.END, f"  최적 비용 = {best_cost:.6e}\n\n")

            self.fit_result_text.insert(tk.END, "[속도별 비교]\n")
            self.fit_result_text.insert(tk.END, f"  {'v(m/s)':>10s}  {'실측':>10s}  {'모델':>10s}  {'오차':>10s}\n")
            for i in range(len(v_meas)):
                err = mu_dry_fit[i] - mu_dry_meas[i]
                self.fit_result_text.insert(tk.END,
                    f"  {v_meas[i]:>10.4e}  {mu_dry_meas[i]:>10.6f}  {mu_dry_fit[i]:>10.6f}  {err:>+10.6f}\n")

            self.fit_status_var.set(f"피팅 완료: R²={r_squared:.4f}, RMSE={rmse:.2e}")

            # ── Immediately apply fitted parameters to UI fields ──
            # These are fitting parameters, not fixed constants. The UI should
            # always reflect the latest fitted values.
            self.adh_tau_f0_var.set(f"{opt_tau_f0/1e6:.4f}")
            self.adh_v0_star_var.set(f"{opt_v0_star:.6e}")
            self.adh_c_var.set(f"{opt_c:.6f}")

            # Recalculate and update plots with fitted parameters
            self._calculate_mu_adh_with_params(opt_tau_f0, opt_v0_star, opt_c)

            # Auto-sync fitted parameters to Cold & Hot Branch tab
            try:
                if hasattr(self, 'ch_tau_f0_var'):
                    self._sync_cold_hot_adh_params()
                    print("[AutoFit] 점착 파라미터 → Cold & Hot Branch 탭 자동 동기화 완료")
            except Exception:
                pass

            self._show_status(
                f"자동 피팅 완료!\n"
                f"τ_f0={opt_tau_f0/1e6:.4f} MPa, v₀*={opt_v0_star:.4e} m/s, c={opt_c:.4f}\n"
                f"R²={r_squared:.6f}, RMSE={rmse:.2e}\n"
                f"→ Cold & Hot Branch 탭에 자동 반영됨", 'success')

        except ValueError as e:
            self._show_status(f"입력값 오류: {str(e)}", 'warning')
            self.fit_status_var.set("피팅 실패: 입력값 오류")
        except Exception as e:
            messagebox.showerror("오류", f"자동 피팅 실패:\n{str(e)}")
            self.fit_status_var.set("피팅 실패")
            import traceback
            traceback.print_exc()
        finally:
            self.fit_button.config(state='normal')

    def _calculate_mu_adh_with_params(self, tau_f0, v0_star, c):
        """Calculate μ_adh with specific parameters (used after fitting).

        Same as _calculate_mu_adh but uses provided parameters instead of GUI values.
        """
        try:
            # Auto-sync T_ref from Tab 2 aT data
            if hasattr(self, 'persson_aT_data') and self.persson_aT_data is not None:
                T_ref_C = self.persson_aT_data.get('T_ref', None)
                if T_ref_C is not None:
                    T_ref_K = T_ref_C + 273.15
                    self.adh_T_ref_var.set(f"{T_ref_K:.2f}")

            epsilon = float(self.adh_epsilon_var.get())
            T_ref = float(self.adh_T_ref_var.get())
            k_B = 8.6173e-5
            T_calc_C = float(self.adh_calc_temp_var.get())
            T = T_calc_C + 273.15
            p0_str = self.adh_p0_var.get().strip()
            if not p0_str and hasattr(self, 'sigma_0_var'):
                p0_str = self.sigma_0_var.get()
            p0 = float(p0_str) * 1e6

            area_source = self.adh_area_source_var.get()
            if area_source == "from_mu_visc":
                v_array = self.mu_visc_results['v']
                A_ratio = self.mu_visc_results['P_qmax']
            else:
                fixed_area = float(self.adh_fixed_area_var.get())
                fixed_area = np.clip(fixed_area, 0.0, 1.0)
                if self.mu_visc_results is not None and 'v' in self.mu_visc_results:
                    v_array = self.mu_visc_results['v']
                else:
                    v_array = np.logspace(-4, 1, 50)
                A_ratio = np.full(len(v_array), fixed_area)

            # 항상 cold (기본 온도) aT_prime 사용
            # mu_adh 탭은 cold 조건에서 피팅/계산. Hot 효과는 Cold & Hot Branch 탭에서 적용.
            aT_prime = np.exp((epsilon / k_B) * (1.0 / T - 1.0 / T_ref))
            aT_prime_cold = aT_prime

            v_eff = v_array * aT_prime
            log_ratio = np.log10(v_eff / v0_star)
            tau_f = tau_f0 * np.exp(-c * log_ratio**2)
            mu_adh = (tau_f / p0) * A_ratio

            self.mu_adh_results = {
                'v': v_array,
                'mu_adh': mu_adh,
                'tau_f': tau_f,
                'tau_f_cold': None,
                'A_ratio': A_ratio,
                'aT_prime': aT_prime,
                'aT_prime_cold': aT_prime_cold,
                'v_eff': v_eff,
                'use_flash': False,
                'params': {
                    'tau_f0': tau_f0,
                    'v0_star': v0_star,
                    'c': c,
                    'epsilon': epsilon,
                    'T_ref': T_ref,
                    'T': T,
                    'p0': p0,
                    'area_source': area_source,
                }
            }

            self._update_mu_adh_plots()

        except Exception as e:
            print(f"_calculate_mu_adh_with_params error: {e}")
            import traceback
            traceback.print_exc()

    def _apply_fit_results(self):
        """Apply fitting results back to the adhesion parameter inputs."""
        if self._fit_results is None:
            self._show_status("피팅 결과가 없습니다. 먼저 자동 피팅을 실행하세요.", 'warning')
            return
        tau_f0 = self._fit_results['tau_f0'] / 1e6  # Pa → MPa
        v0_star = self._fit_results['v0_star']
        c = self._fit_results['c']

        self.adh_tau_f0_var.set(f"{tau_f0:.4f}")
        self.adh_v0_star_var.set(f"{v0_star:.6e}")
        self.adh_c_var.set(f"{c:.6f}")

        self._show_status(
            f"피팅 결과가 파라미터에 적용되었습니다.\n"
            f"τ_f0={tau_f0:.4f} MPa, v₀*={v0_star:.4e} m/s, c={c:.6f}", 'success')

    def _complete_adh_fitting(self):
        """Finalize μ_adh fitting - apply results and exit fitting mode.

        After pressing this button:
        - Fitted parameters (τ_f0, v₀*, c) are applied and locked
        - Fitting controls are disabled
        - Temperature changes only shift the τ_f curve via Arrhenius (no re-fitting)
        """
        if self._fit_results is None:
            self._show_status("피팅 결과가 없습니다. 먼저 자동 피팅을 실행하세요.", 'warning')
            return

        # Apply fit results to parameter fields
        self._apply_fit_results()

        # Mark fitting as completed
        self._adh_fitting_completed = True

        # Disable fitting controls
        self.fit_button.config(state='disabled')
        self.fit_complete_button.config(state='disabled')

        # Update status
        r_sq = self._fit_results.get('r_squared', 0)
        rmse = self._fit_results.get('rmse', 0)
        self.fit_status_var.set(
            f"피팅 확정 완료 (R²={r_sq:.4f}) — 온도 변경 시 전단응력 곡선만 이동됩니다")

        self._show_status(
            "mu_adh 피팅이 확정되었습니다.\n"
            "이제 계산 온도를 변경하면 완성된 전단응력 곡선이\n"
            "Arrhenius 이동만 적용됩니다.\n"
            "피팅을 다시 하려면 '피팅 초기화' 버튼을 누르세요.", 'success')

    def _reset_adh_fitting(self):
        """Reset μ_adh fitting state to allow re-fitting from scratch.

        - Clears all fit results
        - Re-enables fitting controls
        - Resets parameter fields to defaults
        - Also clears previously loaded μ_visc and A/A0 data so they are
          recalculated fresh for the next fitting round.
        """
        # Clear fitting state
        self._adh_fitting_completed = False
        self._fit_results = None

        # Re-enable fitting controls
        self.fit_button.config(state='normal')
        self.fit_complete_button.config(state='normal')

        # Reset parameter fields to defaults
        self.adh_tau_f0_var.set("6.5")
        self.adh_v0_star_var.set("10")
        self.adh_c_var.set("0.1")

        # Reset fitting bounds to defaults
        self.fit_tau_min_var.set("0.1")
        self.fit_tau_max_var.set("50.0")
        self.fit_v0_min_var.set("1e-6")
        self.fit_v0_max_var.set("50")
        self.fit_c_min_var.set("0.001")
        self.fit_c_max_var.set("5.0")
        self.fit_de_count_var.set("1")

        # Clear fit result text
        self.fit_result_text.delete(1.0, tk.END)

        # Clear stored μ_adh results
        self.mu_adh_results = None

        # ── Also reset μ_visc results so stale data doesn't persist ──
        self.mu_visc_results = None
        self.adh_area_status_var.set("A/A0: μ_visc 결과 대기 중 (초기화됨)")
        self.adh_sync_status_var.set("(μ_visc 재계산 필요)")

        # Clear plots (including twin axis)
        self.ax_adh_tau.clear()
        if hasattr(self, '_ax_adh_tau_twin') and self._ax_adh_tau_twin is not None:
            self._ax_adh_tau_twin.remove()
            self._ax_adh_tau_twin = None
        self.ax_adh_mu.clear()
        self.ax_adh_total.clear()
        self.ax_adh_area.clear()
        for ax in [self.ax_adh_tau, self.ax_adh_mu, self.ax_adh_total]:
            ax.set_xscale('log')
            ax.grid(True, alpha=0.3)
        self.ax_adh_area.grid(True, alpha=0.3)  # aT plot uses linear x-axis
        self.ax_adh_tau.set_title('점착 전단 응력 τ_f(v) + A/A0', fontweight='bold', fontsize=11)
        self.ax_adh_tau.set_xlabel('속도 v (m/s)', fontsize=11)
        self.ax_adh_tau.set_ylabel('τ_f (MPa)', fontsize=11)
        self.ax_adh_mu.set_title('μ_adh(v) 곡선', fontweight='bold', fontsize=11)
        self.ax_adh_mu.set_xlabel('속도 v (m/s)', fontsize=11)
        self.ax_adh_mu.set_ylabel('마찰 계수 μ_adh', fontsize=11)
        self.ax_adh_total.set_title('μ_total = μ_visc + μ_adh', fontweight='bold', fontsize=11)
        self.ax_adh_total.set_xlabel('속도 v (m/s)', fontsize=11)
        self.ax_adh_total.set_ylabel('마찰 계수 μ', fontsize=11)
        self.ax_adh_area.set_title('이동 인자 aT 비교', fontweight='bold', fontsize=11)
        self.ax_adh_area.set_xlabel('온도 T (°C)', fontsize=11)
        self.ax_adh_area.set_ylabel('log₁₀(aT)', fontsize=11)
        self.canvas_mu_adh.draw_idle()

        # Clear result text
        self.adh_result_text.delete(1.0, tk.END)

        # Update status
        self.fit_status_var.set("피팅 초기화 완료 — μ_visc 재계산 후 피팅 실행")

        self._show_status(
            "μ_adh 피팅이 초기화되었습니다.\n"
            "기존 μ_visc / A/A0 데이터도 함께 초기화되었습니다.\n"
            "μ_visc를 재계산한 후 피팅을 다시 시작하세요.", 'success')


    # ================================================================
    # ====  Cold & Hot Branch Tab  ====
    # ================================================================

    def _create_cold_hot_branch_tab(self, parent):
        """Create Cold & Hot Branch analysis tab.

        Implements Persson friction theory Cold/Hot branch generation:
          Module 1: Cold Branch (no flash temperature)
          Module 2: Hot Branch (self-consistent flash temperature iteration)
        """
        layout = self._create_tab_layout(parent, toolbar_buttons=[
            ("Cold & Hot 계산", self._calculate_cold_hot_branch, 'Accent.TButton'),
        ])
        left_panel = layout['content']

        # Internal storage
        self.cold_hot_results = None

        # ── 1) 기본 조건 (Base Conditions) ──
        sec1 = self._create_section(left_panel, "1) 기본 조건")

        # T0: base temperature
        row_t0 = ttk.Frame(sec1)
        row_t0.pack(fill=tk.X, pady=1)
        ttk.Label(row_t0, text="T₀ (기준 온도):", font=self.FONTS['body']).pack(side=tk.LEFT)
        self.ch_T0_var = tk.StringVar(value="20.0")
        ttk.Entry(row_t0, textvariable=self.ch_T0_var, width=8).pack(side=tk.LEFT, padx=2)
        ttk.Label(row_t0, text="°C", font=self.FONTS['small'],
                  foreground='#64748B').pack(side=tk.LEFT)

        # p0: nominal contact pressure
        row_p0 = ttk.Frame(sec1)
        row_p0.pack(fill=tk.X, pady=1)
        ttk.Label(row_p0, text="p₀ (명목 압력):", font=self.FONTS['body']).pack(side=tk.LEFT)
        self.ch_p0_var = tk.StringVar(value="0.3")
        ttk.Entry(row_p0, textvariable=self.ch_p0_var, width=8).pack(side=tk.LEFT, padx=2)
        ttk.Label(row_p0, text="MPa", font=self.FONTS['small'],
                  foreground='#64748B').pack(side=tk.LEFT)

        # D: macro-asperity diameter
        row_D = ttk.Frame(sec1)
        row_D.pack(fill=tk.X, pady=1)
        ttk.Label(row_D, text="D (돌기 직경):", font=self.FONTS['body']).pack(side=tk.LEFT)
        self.ch_D_macro_var = tk.StringVar(value="2.0")
        ttk.Entry(row_D, textvariable=self.ch_D_macro_var, width=8).pack(side=tk.LEFT, padx=2)
        ttk.Label(row_D, text="mm  (s₀ = 0.2D)", font=self.FONTS['small'],
                  foreground='#64748B').pack(side=tk.LEFT)

        # Sync button
        sync_row = ttk.Frame(sec1)
        sync_row.pack(fill=tk.X, pady=2)
