    # ── Cold & Hot Branch: Sync helpers ──

    def _sync_cold_hot_from_tabs(self):
        """Synchronize base conditions from μ_visc and μ_adh tabs."""
        try:
            # Temperature
            if hasattr(self, 'mu_calc_temp_var'):
                self.ch_T0_var.set(self.mu_calc_temp_var.get())
            # Pressure
            if hasattr(self, 'mu_sigma0_var') and self.mu_sigma0_var.get().strip():
                self.ch_p0_var.set(self.mu_sigma0_var.get())
            elif hasattr(self, 'sigma_0_var'):
                self.ch_p0_var.set(self.sigma_0_var.get())
            # Flash temp thermal properties
            if hasattr(self, 'flash_rho_var'):
                self.ch_rho_var.set(self.flash_rho_var.get())
            if hasattr(self, 'flash_cv_var'):
                self.ch_Cv_var.set(self.flash_cv_var.get())
            if hasattr(self, 'flash_kappa_var'):
                self.ch_kappa_var.set(self.flash_kappa_var.get())
            if hasattr(self, 'flash_d_macro_var'):
                self.ch_D_macro_var.set(self.flash_d_macro_var.get())
            # Adhesion params
            self._sync_cold_hot_adh_params()
            # T_ref from aT data
            if hasattr(self, 'persson_aT_data') and self.persson_aT_data is not None:
                T_ref_C = self.persson_aT_data.get('T_ref', None)
                if T_ref_C is not None:
                    T_ref_K = T_ref_C + 273.15
                    self.ch_T_ref_adh_var.set(f"{T_ref_K:.2f}")

            self.ch_sync_status_var.set("동기화 완료")
            self._show_status("Cold & Hot Branch 조건 동기화 완료", 'success')
        except Exception as e:
            self.ch_sync_status_var.set(f"동기화 실패: {e}")

    def _sync_cold_hot_adh_params(self):
        """Sync adhesion parameters from μ_adh tab."""
        try:
            if hasattr(self, 'adh_tau_f0_var'):
                self.ch_tau_f0_var.set(self.adh_tau_f0_var.get())
            if hasattr(self, 'adh_v0_star_var'):
                self.ch_v0_star_var.set(self.adh_v0_star_var.get())
            if hasattr(self, 'adh_c_var'):
                self.ch_c_gauss_var.set(self.adh_c_var.get())
            if hasattr(self, 'adh_epsilon_var'):
                self.ch_epsilon_var.set(self.adh_epsilon_var.get())
            if hasattr(self, 'adh_T_ref_var'):
                self.ch_T_ref_adh_var.set(self.adh_T_ref_var.get())
        except Exception:
            pass

    # ── Cold & Hot Branch: Main calculation ──

    def _calculate_cold_hot_branch(self):
        """Cold & Hot Branch using pre-computed μ_visc / μ_adh tab data.

        Cold: mu_visc_results['mu'] (cold hys) + mu_adh_results['mu_adh'] (cold adh)
        Hot hys: mu_visc_results['mu_hot']
        Hot adh: A_A0_hot × tau_f_hot(T_hot) / p0
                 tau_f_hot recalculated with Arrhenius aT' at T_hot
        """
        try:
            self.ch_calc_button.config(state='disabled')
            self.ch_progress_var.set(0)
            self.status_var.set("Cold & Hot Branch 계산 시작...")
            self.root.update()

            from scipy.interpolate import interp1d

            # ── Validate: μ_visc results must exist ──
            if not hasattr(self, 'mu_visc_results') or self.mu_visc_results is None:
                self._show_status(
                    "μ_visc 결과가 없습니다.\n"
                    "μ_visc 탭에서 먼저 계산을 실행하세요.", 'warning')
                self.ch_calc_button.config(state='normal')
                return

            # ── Validate: μ_adh results must exist ──
            if not hasattr(self, 'mu_adh_results') or self.mu_adh_results is None:
                self._show_status(
                    "μ_adh 결과가 없습니다.\n"
                    "μ_adh 탭에서 먼저 계산을 실행하세요.", 'warning')
                self.ch_calc_button.config(state='normal')
                return

            # ── Validate: Flash (Hot) data must exist in μ_visc ──
            mu_hot_from_visc = self.mu_visc_results.get('mu_hot')
            A_A0_hot_from_visc = self.mu_visc_results.get('A_A0_hot')
            if mu_hot_from_visc is None or A_A0_hot_from_visc is None:
                self._show_status(
                    "Flash Temperature (Hot) 데이터가 없습니다.\n"
                    "μ_visc 탭에서 Flash ON으로 계산하세요.", 'warning')
                self.ch_calc_button.config(state='normal')
                return

            self.ch_progress_var.set(10)
            self.root.update()

            # ══════════════════════════════════════════
            # Cold Branch: μ_visc + μ_adh 탭 데이터 직접 사용
            # ══════════════════════════════════════════
            self.status_var.set("Cold Branch: μ_visc/μ_adh 탭 데이터 로드 중...")
            self.root.update()

            v_visc = self.mu_visc_results['v']
            v_adh = self.mu_adh_results['v']
            v_array = v_visc
            n_v = len(v_array)

            # Cold hysteresis: μ_visc 탭의 mu (cold, base temperature)
            mu_cold_hys = self.mu_visc_results['mu'].copy()

            # Cold A/A0: μ_visc 탭의 A_A0_cold 또는 P_qmax
            A_A0_cold = self.mu_visc_results.get('A_A0_cold')
            if A_A0_cold is None:
                A_A0_cold = self.mu_visc_results.get('P_qmax', np.zeros(n_v))
            if A_A0_cold is not None:
                A_A0_cold = A_A0_cold.copy()
            else:
                A_A0_cold = np.zeros(n_v)

            # Cold adhesion + tau_f: μ_adh 탭 데이터
            mu_adh_cold_raw = self.mu_adh_results['mu_adh']
            tau_f_raw = self.mu_adh_results['tau_f']
            p0 = self.mu_adh_results['params']['p0']    # Pa

            # 속도 배열이 다를 경우 보간
            if len(v_adh) == len(v_visc) and np.allclose(v_adh, v_visc):
                mu_cold_ad = mu_adh_cold_raw.copy()
                tau_f = tau_f_raw.copy()
            else:
                log_v_adh = np.log10(np.maximum(v_adh, 1e-30))
                log_v_visc = np.log10(np.maximum(v_visc, 1e-30))
                mu_cold_ad = np.interp(log_v_visc, log_v_adh, mu_adh_cold_raw)
                tau_f = np.interp(log_v_visc, log_v_adh, tau_f_raw)

            mu_cold_total = mu_cold_hys + mu_cold_ad

            self.ch_progress_var.set(30)
            self.root.update()

            # ══════════════════════════════════════════
            # Hot Branch: μ_visc 탭의 mu_hot + A_A0_hot × tau_f_hot(T_hot) / p0
            # tau_f_hot: Arrhenius aT'(T_hot)로 재계산
            # ══════════════════════════════════════════
            self.status_var.set("Hot Branch: μ_visc 탭 Flash 데이터 로드 중...")
            self.root.update()

            # Hot hysteresis: μ_visc 탭의 mu_hot 그대로
            mu_hot_hys = mu_hot_from_visc.copy()

            # Hot A/A0: μ_visc 탭의 A_A0_hot 그대로
            A_A0_hot = A_A0_hot_from_visc.copy()

            # Flash temp data from μ_visc (needed for Arrhenius aT at T_hot)
            flash_results = self.mu_visc_results.get('flash_results')
            if flash_results is not None:
                delta_T_arr = np.array(flash_results.get('delta_T', np.zeros(n_v)))
                T_hot_arr = np.array(flash_results.get('T_hot', np.zeros(n_v)))
            else:
                delta_T_arr = np.zeros(n_v)
                T_hot_arr = np.full(n_v, float(self.ch_T0_var.get()))

            # Hot adhesion = A_A0_hot × tau_f_hot / p0
            # tau_f_hot: per-velocity aT'(T_hot(v))로 각 속도별 Arrhenius 시프트
            # 속도가 빨라질수록 T_hot 상승 → aT' 감소 → 피크가 고속으로 이동
            # 결과: 오른쪽 꼬리가 길게 잡아 늘여진(Stretched) 비대칭 형태
            adh_params = self.mu_adh_results['params']
            tau_f0_val = adh_params['tau_f0']   # Pa
            v0_star_val = adh_params['v0_star']  # m/s
            c_val = adh_params['c']
            epsilon_val = adh_params['epsilon']  # eV
            T_ref_val = adh_params['T_ref']      # K
            k_B = 8.6173e-5                       # eV/K

            # Cold aT' (single scalar, same as mu_adh tab)
            T_cold_K = adh_params['T'] if 'T' in adh_params else (float(self.ch_T0_var.get()) + 273.15)
            aT_prime_cold = np.exp((epsilon_val / k_B) * (1.0 / T_cold_K - 1.0 / T_ref_val))

            # Per-velocity aT'(T_hot(v)): 각 속도에서의 플래시 온도로 개별 시프트
            T_hot_arr_K = T_hot_arr + 273.15  # °C → K (array)
            aT_prime_hot = np.exp((epsilon_val / k_B) * (1.0 / T_hot_arr_K - 1.0 / T_ref_val))

            # tau_f_hot: per-velocity Arrhenius shifted Gaussian
            # v_eff(v) = v × aT'(T_hot(v)), tau_f = tau_f0 × exp[-c × (log10(v_eff/v0*))²]
            v_eff_hot = v_array * aT_prime_hot
            log_ratio_hot = np.log10(v_eff_hot / v0_star_val)
            tau_f_hot = tau_f0_val * np.exp(-c_val * log_ratio_hot**2)

            print(f"[Cold&Hot] tau_f per-velocity shift: "
                  f"aT_cold={aT_prime_cold:.4e}, "
                  f"aT_hot range=[{np.min(aT_prime_hot):.4e}, {np.max(aT_prime_hot):.4e}], "
                  f"T_hot range=[{np.min(T_hot_arr):.1f}, {np.max(T_hot_arr):.1f}]°C")

            mu_hot_ad = (A_A0_hot * tau_f_hot) / p0
            mu_hot_total = mu_hot_hys + mu_hot_ad

            self.ch_progress_var.set(60)
            self.root.update()

            # ── Read base parameters ──
            T0 = float(self.ch_T0_var.get())
            p0_MPa = float(self.ch_p0_var.get())
            sigma_0 = p0_MPa * 1e6
            D_mm = float(self.ch_D_macro_var.get())
            D_m = D_mm * 1e-3
            s0 = 0.2 * D_m

            self.ch_progress_var.set(90)
            self.root.update()

            # ── Store results ──
            self.cold_hot_results = {
                'v': v_array,
                'T0': T0,
                'sigma_0': sigma_0,
                'D': D_m,
                's0': s0,
                # Cold branch (from μ_visc + μ_adh tabs)
                'mu_cold_hys': mu_cold_hys,
                'mu_cold_ad': mu_cold_ad,
                'mu_cold_total': mu_cold_total,
                'A_A0_cold': A_A0_cold,
                # Hot branch (mu_hot from μ_visc, mu_adh = A_A0_hot × τ_f_hot / p0)
                'mu_hot_hys': mu_hot_hys,
                'mu_hot_ad': mu_hot_ad,
                'mu_hot_total': mu_hot_total,
                'A_A0_hot': A_A0_hot,
                'tau_f_cold': tau_f,          # Cold 전단응력 (Pa)
                'tau_f_hot': tau_f_hot,       # Hot 전단응력 - per-velocity Arrhenius shifted (Pa)
                'aT_prime_hot': aT_prime_hot, # Hot Arrhenius shift factor (per-velocity array)
                'aT_prime_cold': aT_prime_cold,  # Cold Arrhenius shift factor (scalar)
                'delta_T': delta_T_arr,
                'T_hot': T_hot_arr,
                'hot_converged': np.ones(n_v, dtype=bool),
                'hot_iters': np.zeros(n_v, dtype=int),
            }

            # ── Update plots ──
            self._update_cold_hot_plots()

            # ── Update result text ──
            self._update_cold_hot_result_text()

            self.ch_progress_var.set(100)
            self.status_var.set("Cold & Hot Branch 계산 완료")
            self.ch_calc_button.config(state='normal')

            self._show_status(
                f"Cold & Hot Branch 완료 ({n_v}점)\n"
                f"데이터 출처: μ_visc + μ_adh 탭 계산 결과\n"
                f"Hot μ_adh = A/A0_hot × τ_f_hot(T_hot) / p0 (Arrhenius aT shifted)\n"
                f"ΔT 범위: {np.min(delta_T_arr):.1f}~{np.max(delta_T_arr):.1f}°C",
                'success')

        except ValueError as e:
            self.ch_calc_button.config(state='normal')
            self._show_status(f"입력값 오류: {str(e)}", 'warning')
        except Exception as e:
            self.ch_calc_button.config(state='normal')
            messagebox.showerror("오류", f"Cold & Hot Branch 계산 실패:\n{str(e)}")
            import traceback
            traceback.print_exc()

    # ── Cold & Hot Branch: Plot update ──

    def _update_cold_hot_plots(self):
        """Update all 4 subplots for Cold & Hot Branch results."""
        if self.cold_hot_results is None:
            return

        try:
            r = self.cold_hot_results
            v = r['v']

            # Clear all subplots
            self.ax_ch_hys.clear()
            self.ax_ch_adh.clear()
            self.ax_ch_flash.clear()
            # Remove old twin axes
            if hasattr(self, '_ax_ch_flash_twin') and self._ax_ch_flash_twin is not None:
                self._ax_ch_flash_twin.remove()
                self._ax_ch_flash_twin = None
            self.ax_ch_total.clear()

            def smart_fmt(val):
                if abs(val) < 0.001 and val != 0:
                    return f'{val:.2e}'
                return f'{val:.4f}'

            # ── Plot 1: μ_hys Cold vs Hot ──
            self.ax_ch_hys.semilogx(v, r['mu_cold_hys'], 'b-', linewidth=2,
                                     label='μ_hys (Cold)')
            self.ax_ch_hys.semilogx(v, r['mu_hot_hys'], 'r-', linewidth=2,
                                     label='μ_hys (Hot)')
            # Mark peaks
            cold_peak = np.argmax(r['mu_cold_hys'])
            hot_peak = np.argmax(r['mu_hot_hys'])
            self.ax_ch_hys.plot(v[cold_peak], r['mu_cold_hys'][cold_peak], 'b*',
                                markersize=12,
                                label=f'Cold max: {smart_fmt(r["mu_cold_hys"][cold_peak])}')
            self.ax_ch_hys.plot(v[hot_peak], r['mu_hot_hys'][hot_peak], 'r*',
                                markersize=12,
                                label=f'Hot max: {smart_fmt(r["mu_hot_hys"][hot_peak])}')
            self.ax_ch_hys.set_title('μ_hys: Cold vs Hot Branch', fontweight='bold', fontsize=10)
            self.ax_ch_hys.set_xlabel('v (m/s)', fontsize=10)
            self.ax_ch_hys.set_ylabel('μ_hys', fontsize=10)
            self.ax_ch_hys.legend(loc='best', fontsize=7)
            self.ax_ch_hys.grid(True, alpha=0.3)

            # ── Plot 2: μ_ad Cold vs Hot (Arrhenius aT) ──
            self.ax_ch_adh.semilogx(v, r['mu_cold_ad'], 'b-', linewidth=2,
                                     label='μ_ad (Cold)')
            self.ax_ch_adh.semilogx(v, r['mu_hot_ad'], 'r-', linewidth=2,
                                     label='μ_ad (Hot, aT shifted)')
            # Mark peaks
            cold_ad_peak = np.argmax(r['mu_cold_ad'])
            hot_ad_peak = np.argmax(r['mu_hot_ad'])
            self.ax_ch_adh.plot(v[cold_ad_peak], r['mu_cold_ad'][cold_ad_peak],
                                'b*', markersize=12,
                                label=f'Cold max: {smart_fmt(r["mu_cold_ad"][cold_ad_peak])}')
            self.ax_ch_adh.plot(v[hot_ad_peak], r['mu_hot_ad'][hot_ad_peak],
                                'r*', markersize=12,
                                label=f'Hot max: {smart_fmt(r["mu_hot_ad"][hot_ad_peak])}')
            self.ax_ch_adh.set_title('μ_ad: Cold vs Hot (Arrhenius aT)', fontweight='bold', fontsize=10)
            self.ax_ch_adh.set_xlabel('v (m/s)', fontsize=10)
            self.ax_ch_adh.set_ylabel('μ_ad', fontsize=10)
            self.ax_ch_adh.legend(loc='best', fontsize=7)
            self.ax_ch_adh.grid(True, alpha=0.3)

            # ── Plot 3: A/A0 + τ_f (shear stress) dual y-axis ──
            line_ac = self.ax_ch_flash.semilogx(v, r['A_A0_cold'], 'b-', linewidth=2,
                                                  marker='o', markersize=3, label='A/A0 (Cold)')
            line_ah = self.ax_ch_flash.semilogx(v, r['A_A0_hot'], '-', color='#DC2626',
                                                  linewidth=2, marker='s', markersize=3,
                                                  label='A/A0 (Hot)')
            self.ax_ch_flash.set_title('A/A0 + τ_f: Cold vs Hot', fontweight='bold', fontsize=10)
            self.ax_ch_flash.set_xlabel('v (m/s)', fontsize=10)
            self.ax_ch_flash.set_ylabel('A/A0', fontsize=10, color='b')
            self.ax_ch_flash.tick_params(axis='y', labelcolor='b')

            # τ_f (shear stress) on twin axis
            self._ax_ch_flash_twin = self.ax_ch_flash.twinx()
            tau_f_cold_MPa = r['tau_f_cold'] / 1e6  # Pa → MPa
            tau_f_hot_MPa = r['tau_f_hot'] / 1e6    # Pa → MPa
            line_tc = self._ax_ch_flash_twin.semilogx(v, tau_f_cold_MPa, 'b--', linewidth=1.5,
                                                       alpha=0.7, label='τ_f Cold (MPa)')
            line_th = self._ax_ch_flash_twin.semilogx(v, tau_f_hot_MPa, '--', color='#DC2626',
                                                       linewidth=1.5, alpha=0.7,
                                                       label='τ_f Hot (MPa)')
            self._ax_ch_flash_twin.set_ylabel('τ_f (MPa)', fontsize=10, color='#666666')
            self._ax_ch_flash_twin.tick_params(axis='y', labelcolor='#666666')

            lines = line_ac + line_ah + line_tc + line_th
            labels = [l.get_label() for l in lines]
            self.ax_ch_flash.legend(lines, labels, loc='best', fontsize=7)
            self.ax_ch_flash.grid(True, alpha=0.3)

            # ── Plot 4: μ_total Cold vs Hot ──
            self.ax_ch_total.semilogx(v, r['mu_cold_total'], 'b-', linewidth=2.5,
                                       label='μ_total (Cold)')
            self.ax_ch_total.semilogx(v, r['mu_hot_total'], 'r-', linewidth=2.5,
                                       label='μ_total (Hot)')
            # Individual components as dashed
            self.ax_ch_total.semilogx(v, r['mu_cold_hys'], 'b--', linewidth=1, alpha=0.5,
                                       label='μ_hys (Cold)')
            self.ax_ch_total.semilogx(v, r['mu_cold_ad'], 'b:', linewidth=1, alpha=0.5,
                                       label='μ_ad (Cold)')
            self.ax_ch_total.semilogx(v, r['mu_hot_hys'], 'r--', linewidth=1, alpha=0.5,
                                       label='μ_hys (Hot)')
            self.ax_ch_total.semilogx(v, r['mu_hot_ad'], 'r:', linewidth=1, alpha=0.5,
                                       label='μ_ad (Hot)')
            # Mark peaks
            cold_total_peak = np.argmax(r['mu_cold_total'])
            hot_total_peak = np.argmax(r['mu_hot_total'])
            self.ax_ch_total.plot(v[cold_total_peak], r['mu_cold_total'][cold_total_peak],
                                  'b*', markersize=12,
                                  label=f'Cold max: {smart_fmt(r["mu_cold_total"][cold_total_peak])}')
            self.ax_ch_total.plot(v[hot_total_peak], r['mu_hot_total'][hot_total_peak],
                                  'r*', markersize=12,
                                  label=f'Hot max: {smart_fmt(r["mu_hot_total"][hot_total_peak])}')
            self.ax_ch_total.set_title('μ_total: Cold vs Hot (hys+ad)', fontweight='bold', fontsize=10)
            self.ax_ch_total.set_xlabel('v (m/s)', fontsize=10)
            self.ax_ch_total.set_ylabel('μ_total', fontsize=10)
            self.ax_ch_total.legend(loc='best', fontsize=6)
            self.ax_ch_total.grid(True, alpha=0.3)

            self.fig_cold_hot.subplots_adjust(left=0.10, right=0.90, top=0.96, bottom=0.08,
                                               hspace=0.50, wspace=0.40)
            self.canvas_cold_hot.draw()

        except Exception as e:
            print(f"Cold & Hot plot update error: {e}")
            import traceback
            traceback.print_exc()

    # ── Cold & Hot Branch: Result text ──

    def _update_cold_hot_result_text(self):
        """Update result text box with Cold & Hot Branch calculation summary."""
        if self.cold_hot_results is None:
            return

        r = self.cold_hot_results
        v = r['v']
        n_v = len(v)

        def smart_fmt(val):
            if abs(val) < 0.001 and val != 0:
                return f'{val:.2e}'
            return f'{val:.4f}'

        txt = self.ch_result_text
        txt.delete(1.0, tk.END)
        txt.insert(tk.END, "=" * 40 + "\n")
        txt.insert(tk.END, "Cold & Hot Branch 계산 결과\n")
        txt.insert(tk.END, "=" * 40 + "\n\n")

        txt.insert(tk.END, f"[데이터 출처]\n")
        txt.insert(tk.END, f"  Cold μ_hys: μ_visc 탭 계산 결과\n")
        txt.insert(tk.END, f"  Cold μ_adh: μ_adh 탭 계산 결과\n")
        txt.insert(tk.END, f"  Hot μ_hys:  μ_visc 탭 mu_hot (Flash)\n")
        txt.insert(tk.END, f"  Hot μ_adh:  A/A0_hot × τ_f_hot(T_hot(v)) / p₀\n")
        txt.insert(tk.END, f"    (Per-velocity Arrhenius aT'(T_hot(v)) — stretched 형태)\n")
        if 'T_hot' in r and np.any(r['T_hot'] > 0):
            txt.insert(tk.END, f"    T_hot 범위: {np.min(r['T_hot']):.1f}~{np.max(r['T_hot']):.1f}°C\n")
            txt.insert(tk.END, f"    aT'_hot 범위: {np.min(r['aT_prime_hot']):.4e}~{np.max(r['aT_prime_hot']):.4e}\n\n")
        else:
            txt.insert(tk.END, "\n")

        txt.insert(tk.END, f"[기본 조건]\n")
        txt.insert(tk.END, f"  T₀={r['T0']:.1f}°C, σ₀={r['sigma_0']/1e6:.3f} MPa\n")
        txt.insert(tk.END, f"  D={r['D']*1e3:.2f} mm, s₀={r['s0']*1e3:.4f} mm\n\n")

        txt.insert(tk.END, f"[Cold Branch (T = T₀)]\n")
        txt.insert(tk.END, f"  μ_hys: {smart_fmt(np.min(r['mu_cold_hys']))} ~ {smart_fmt(np.max(r['mu_cold_hys']))}\n")
        txt.insert(tk.END, f"  μ_ad:  {smart_fmt(np.min(r['mu_cold_ad']))} ~ {smart_fmt(np.max(r['mu_cold_ad']))}\n")
        txt.insert(tk.END, f"  μ_tot: {smart_fmt(np.min(r['mu_cold_total']))} ~ {smart_fmt(np.max(r['mu_cold_total']))}\n")
        cold_peak = np.argmax(r['mu_cold_total'])
        txt.insert(tk.END, f"  최대: μ={smart_fmt(r['mu_cold_total'][cold_peak])} @ v={v[cold_peak]:.2e}\n\n")

        txt.insert(tk.END, f"[Hot Branch (T = T₀ + ΔT)]\n")
        txt.insert(tk.END, f"  μ_hys: {smart_fmt(np.min(r['mu_hot_hys']))} ~ {smart_fmt(np.max(r['mu_hot_hys']))}\n")
        txt.insert(tk.END, f"  μ_ad:  {smart_fmt(np.min(r['mu_hot_ad']))} ~ {smart_fmt(np.max(r['mu_hot_ad']))}\n")
        txt.insert(tk.END, f"  μ_tot: {smart_fmt(np.min(r['mu_hot_total']))} ~ {smart_fmt(np.max(r['mu_hot_total']))}\n")
        hot_peak = np.argmax(r['mu_hot_total'])
        txt.insert(tk.END, f"  최대: μ={smart_fmt(r['mu_hot_total'][hot_peak])} @ v={v[hot_peak]:.2e}\n")
        txt.insert(tk.END, f"  ΔT: {np.min(r['delta_T']):.1f} ~ {np.max(r['delta_T']):.1f}°C\n")
        n_conv = np.sum(r['hot_converged'])
        txt.insert(tk.END, f"  수렴: {n_conv}/{n_v}\n\n")

        # Sample velocity table
        txt.insert(tk.END, f"[속도별 요약]\n")
        txt.insert(tk.END, f"{'v(m/s)':>12s} {'μ_C_hys':>8s} {'μ_C_ad':>8s} {'μ_C_tot':>8s} "
                            f"{'μ_H_hys':>8s} {'μ_H_ad':>8s} {'μ_H_tot':>8s} {'ΔT':>6s}\n")
        step = max(1, n_v // 10)
        for i in range(0, n_v, step):
            txt.insert(tk.END,
                f"{v[i]:12.2e} {r['mu_cold_hys'][i]:8.4f} {r['mu_cold_ad'][i]:8.4f} "
                f"{r['mu_cold_total'][i]:8.4f} {r['mu_hot_hys'][i]:8.4f} "
                f"{r['mu_hot_ad'][i]:8.4f} {r['mu_hot_total'][i]:8.4f} "
                f"{r['delta_T'][i]:6.1f}\n")

    # ── Cold & Hot Branch: CSV export ──

    def _export_cold_hot_csv(self):
        """Export Cold & Hot Branch results to CSV."""
        if self.cold_hot_results is None:
            self._show_status("Cold & Hot Branch 결과가 없습니다.", 'warning')
            return

        mc_prefix = self._get_mc_prefix() if hasattr(self, '_get_mc_prefix') else ''
        default_fn = f"{mc_prefix}_cold_hot_branch.csv" if mc_prefix else "cold_hot_branch.csv"

        filepath = filedialog.asksaveasfilename(
            title="Cold & Hot Branch 데이터 내보내기",
            defaultextension=".csv",
            filetypes=[("CSV", "*.csv"), ("텍스트", "*.txt")],
            initialfile=default_fn
        )
        if not filepath:
            return

        try:
            from datetime import datetime
            r = self.cold_hot_results
            v = r['v']

            lines = [
                f"# Cold & Hot Branch Results",
                f"# 생성일시,{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
                f"# T0 (°C),{r['T0']:.1f}",
                f"# sigma_0 (MPa),{r['sigma_0']/1e6:.3f}",
                f"# D (mm),{r['D']*1e3:.2f}",
                f"# s0 (mm),{r['s0']*1e3:.4f}",
                "#",
                "log10(v),v [m/s],mu_cold_hys,mu_cold_ad,mu_cold_total,"
                "mu_hot_hys,mu_hot_ad,mu_hot_total,A_A0_cold,A_A0_hot,delta_T,T_hot,converged"
            ]
            for i in range(len(v)):
                lines.append(
                    f"{np.log10(v[i]):.6f},{v[i]:.6e},"
                    f"{r['mu_cold_hys'][i]:.6f},{r['mu_cold_ad'][i]:.6f},{r['mu_cold_total'][i]:.6f},"
                    f"{r['mu_hot_hys'][i]:.6f},{r['mu_hot_ad'][i]:.6f},{r['mu_hot_total'][i]:.6f},"
                    f"{r['A_A0_cold'][i]:.6f},{r['A_A0_hot'][i]:.6f},"
                    f"{r['delta_T'][i]:.2f},{r['T_hot'][i]:.2f},{int(r['hot_converged'][i])}"
                )

            with open(filepath, 'w', encoding='utf-8-sig') as f:
                f.write("\n".join(lines))

            self._show_status(f"Cold & Hot Branch CSV 저장 완료: {filepath}", 'success')
        except Exception as e:
            messagebox.showerror("오류", f"CSV 저장 실패:\n{str(e)}")



    # ================================================================
    # ====  Friction Map (3D LUT: Temperature × Pressure × Velocity)  ====
    # ================================================================

    def _create_friction_map_tab(self, parent):
        """Create Friction Map tab for generating 3D look-up tables.

        Generates Cold and Hot friction maps (μ_total vs T0, p0, v)
        that can be used as LUTs for the 2D Brush tire dynamics model.
        """
        layout = self._create_tab_layout(parent, toolbar_buttons=[
            ("시험 Run", self._test_run_pipeline, 'TButton'),
            ("Friction Map 생성", self._calculate_friction_map, 'Accent.TButton'),
            ("LUT 내보내기 (CSV)", self._export_friction_map_csv, 'TButton'),
        ])
        left_panel = layout['content']

        # Internal storage
        self.friction_map_results = None

        # ── Right panel: Notebook with 3D Map + 2D Graph tabs ──
        right_panel = layout.get('right')
        self.fm_right_notebook = ttk.Notebook(right_panel)
        self.fm_right_notebook.pack(fill=tk.BOTH, expand=True)

        # Tab 1: 3D Map (기존 마찰맵 표면)
        self.friction_map_right = ttk.Frame(self.fm_right_notebook)
        self.fm_right_notebook.add(self.friction_map_right, text='  3D Map  ')
        self._create_fm_3d_toolbar(self.friction_map_right)

        # Tab 2: 2D Graph (선택 가능한 데이터 플롯)
        fm_graph_tab = ttk.Frame(self.fm_right_notebook)
        self.fm_right_notebook.add(fm_graph_tab, text='  Graph  ')
        self._create_fm_graph_tab(fm_graph_tab)

        # ── 1) Sweep 범위 설정 ──
        sec1 = self._create_section(left_panel, "1) Sweep 범위 설정")

        # Temperature axis
        ttk.Label(sec1, text="── 바탕 온도 T₀ (°C) ──", font=self.FONTS['body'],
                  foreground='#0369A1').pack(anchor='w', pady=(4, 0))
        row_t = ttk.Frame(sec1); row_t.pack(fill=tk.X, pady=1)
        ttk.Label(row_t, text="시작:", font=self.FONTS['body']).pack(side=tk.LEFT)
        self.fm_T_start_var = tk.StringVar(value="-20")
        ttk.Entry(row_t, textvariable=self.fm_T_start_var, width=6).pack(side=tk.LEFT, padx=2)
        ttk.Label(row_t, text="끝:", font=self.FONTS['body']).pack(side=tk.LEFT, padx=(6, 0))
        self.fm_T_end_var = tk.StringVar(value="100")
        ttk.Entry(row_t, textvariable=self.fm_T_end_var, width=6).pack(side=tk.LEFT, padx=2)
        ttk.Label(row_t, text="간격:", font=self.FONTS['body']).pack(side=tk.LEFT, padx=(6, 0))
        self.fm_T_step_var = tk.StringVar(value="20")
        ttk.Entry(row_t, textvariable=self.fm_T_step_var, width=5).pack(side=tk.LEFT, padx=2)
        ttk.Label(row_t, text="°C", font=self.FONTS['small'], foreground='#64748B').pack(side=tk.LEFT)

        # Pressure axis
        ttk.Label(sec1, text="── 명목 접촉 압력 p₀ (MPa) ──", font=self.FONTS['body'],
                  foreground='#0369A1').pack(anchor='w', pady=(6, 0))
        row_p_preset = ttk.Frame(sec1); row_p_preset.pack(fill=tk.X, pady=1)
        ttk.Label(row_p_preset, text="프리셋:", font=self.FONTS['body']).pack(side=tk.LEFT)
        self.fm_p0_preset_var = tk.StringVar(value="Simple")
