    def _create_fm_graph_tab(self, parent):
        """Create the 2D graph tab inside Friction Map right panel."""
        from matplotlib.figure import Figure
        from matplotlib.backends.backend_tkagg import FigureCanvasTkAgg, NavigationToolbar2Tk

        # ── Row 1: Data selection radio buttons ──
        ctrl1 = ttk.Frame(parent)
        ctrl1.pack(fill=tk.X, padx=4, pady=(4, 0))

        ttk.Label(ctrl1, text="데이터:", font=('', 10, 'bold')).pack(side=tk.LEFT, padx=(0, 4))
        self.fm_graph_data_var = tk.StringVar(value="mu_total")
        for label, val in [("A/A0", "A_A0"), ("tau_s", "tau_f"),
                           ("mu_hys", "mu_visc"), ("mu_adh", "mu_adh"), ("mu_total", "mu_total"),
                           ("F_hys", "F_visc"), ("F_adh", "F_adh"), ("F_total", "F_total")]:
            ttk.Radiobutton(ctrl1, text=label, variable=self.fm_graph_data_var,
                            value=val, command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)

        ttk.Separator(ctrl1, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=6)
        self.fm_graph_branch_var = tk.StringVar(value="cold")
        ttk.Radiobutton(ctrl1, text="Cold", variable=self.fm_graph_branch_var,
                        value="cold", command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)
        ttk.Radiobutton(ctrl1, text="Hot", variable=self.fm_graph_branch_var,
                        value="hot", command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)

        ttk.Separator(ctrl1, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=6)
        self.fm_graph_overlay_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(ctrl1, text="탭 검증 오버레이", variable=self.fm_graph_overlay_var,
                        command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)

        # ── Row 2: Condition selection (T, p0 filter) ──
        ctrl2 = ttk.Frame(parent)
        ctrl2.pack(fill=tk.X, padx=4, pady=(2, 0))

        ttk.Label(ctrl2, text="플롯 모드:", font=('', 10, 'bold')).pack(side=tk.LEFT, padx=(0, 4))
        self.fm_graph_mode_var = tk.StringVar(value="fix_T")
        ttk.Radiobutton(ctrl2, text="T 고정 (p0별 비교)", variable=self.fm_graph_mode_var,
                        value="fix_T", command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)
        ttk.Radiobutton(ctrl2, text="p0 고정 (T별 비교)", variable=self.fm_graph_mode_var,
                        value="fix_p0", command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)
        ttk.Radiobutton(ctrl2, text="전체", variable=self.fm_graph_mode_var,
                        value="all", command=self._update_fm_graph).pack(side=tk.LEFT, padx=2)

        ttk.Separator(ctrl2, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=6)
        ttk.Label(ctrl2, text="T:", font=('', 10)).pack(side=tk.LEFT, padx=(0, 2))
        self.fm_graph_T_var = tk.StringVar()
        self.fm_graph_T_combo = ttk.Combobox(ctrl2, textvariable=self.fm_graph_T_var,
                                              width=6, state='readonly')
        self.fm_graph_T_combo.pack(side=tk.LEFT, padx=2)
        self.fm_graph_T_combo.bind('<<ComboboxSelected>>', lambda e: self._update_fm_graph())
        ttk.Label(ctrl2, text="°C", font=('', 9)).pack(side=tk.LEFT)

        ttk.Label(ctrl2, text="p0:", font=('', 10)).pack(side=tk.LEFT, padx=(8, 2))
        self.fm_graph_p0_var = tk.StringVar()
        self.fm_graph_p0_combo = ttk.Combobox(ctrl2, textvariable=self.fm_graph_p0_var,
                                               width=6, state='readonly')
        self.fm_graph_p0_combo.pack(side=tk.LEFT, padx=2)
        self.fm_graph_p0_combo.bind('<<ComboboxSelected>>', lambda e: self._update_fm_graph())
        ttk.Label(ctrl2, text="MPa", font=('', 9)).pack(side=tk.LEFT)

        # ── Figure ──
        plot_frame = ttk.Frame(parent)
        plot_frame.pack(fill=tk.BOTH, expand=True, padx=4, pady=(2, 4))

        self.fig_fm_graph = Figure(figsize=(9, 6), dpi=100)
        self.ax_fm_graph = self.fig_fm_graph.add_subplot(111)
        self.fig_fm_graph.subplots_adjust(left=0.10, right=0.95, top=0.92, bottom=0.12)

        self.canvas_fm_graph = FigureCanvasTkAgg(self.fig_fm_graph, plot_frame)
        self.canvas_fm_graph.draw_idle()
        self.canvas_fm_graph.get_tk_widget().pack(fill=tk.BOTH, expand=True)

        toolbar = NavigationToolbar2Tk(self.canvas_fm_graph, plot_frame)
        toolbar.update()

    def _update_fm_graph(self):
        """Update the 2D graph based on selected data type, branch, and filter."""
        r = self.friction_map_results
        if r is None:
            return

        ax = self.ax_fm_graph
        ax.clear()

        data_key = self.fm_graph_data_var.get()
        branch = self.fm_graph_branch_var.get()
        show_overlay = self.fm_graph_overlay_var.get()
        mode = self.fm_graph_mode_var.get()

        T_arr = r['T_array']
        p0_arr = r['p0_array_MPa']
        v_arr = r['v_array']

        # Update combo values if not set
        T_vals = [f"{t:.0f}" for t in T_arr]
        p0_vals = [f"{p:.4g}" for p in p0_arr]
        self.fm_graph_T_combo['values'] = T_vals
        self.fm_graph_p0_combo['values'] = p0_vals
        if not self.fm_graph_T_var.get() and T_vals:
            self.fm_graph_T_var.set(T_vals[len(T_vals) // 2])
        if not self.fm_graph_p0_var.get() and p0_vals:
            self.fm_graph_p0_var.set(p0_vals[len(p0_vals) // 2])

        # Select LUT — handle F_ (force) keys by mapping to mu LUT × p0
        is_force = data_key.startswith('F_')
        if is_force:
            mu_key = data_key.replace('F_', '', 1)  # F_visc→visc, F_adh→adh, F_total→total
        else:
            mu_key = data_key

        suffix = '_cold' if branch == 'cold' else '_hot'
        if mu_key in ('mu_total', 'total'):
            lut_key = 'LUT_cold' if branch == 'cold' else 'LUT_hot'
        elif mu_key == 'visc':
            lut_key = f'LUT_mu_visc{suffix}'
        elif mu_key == 'adh':
            lut_key = f'LUT_mu_adh{suffix}'
        else:
            lut_key = f'LUT_{mu_key}{suffix}'
        LUT = r.get(lut_key)
        if LUT is None:
            return

        # Determine which T, p0 indices to plot
        if mode == 'fix_T':
            try:
                sel_T = float(self.fm_graph_T_var.get())
                i_T = int(np.argmin(np.abs(T_arr - sel_T)))
            except (ValueError, TypeError):
                i_T = len(T_arr) // 2
            T_indices = [i_T]
            p0_indices = list(range(len(p0_arr)))
        elif mode == 'fix_p0':
            try:
                sel_p0 = float(self.fm_graph_p0_var.get())
                i_p = int(np.argmin(np.abs(p0_arr - sel_p0)))
            except (ValueError, TypeError):
                i_p = len(p0_arr) // 2
            T_indices = list(range(len(T_arr)))
            p0_indices = [i_p]
        else:
            T_indices = list(range(len(T_arr)))
            p0_indices = list(range(len(p0_arr)))

        colors_T = ['#1f77b4', '#ff7f0e', '#2ca02c', '#d62728', '#9467bd',
                     '#8c564b', '#e377c2', '#7f7f7f', '#bcbd22', '#17becf']
        colors_p = ['#1f77b4', '#ff7f0e', '#2ca02c', '#d62728', '#9467bd',
                     '#8c564b', '#e377c2', '#7f7f7f', '#bcbd22', '#17becf']
        line_styles = ['-', '--', '-.', ':', (0, (3, 1, 1, 1)), (0, (5, 2))]

        for i_T in T_indices:
            T0 = T_arr[i_T]
            for i_p in p0_indices:
                p0 = p0_arr[i_p]
                data = LUT[i_T, i_p, :].copy()
                if data_key == 'tau_f':
                    data = data / 1e6
                elif is_force:
                    # F = μ × p₀ (MPa)
                    data = data * p0

                if mode == 'fix_T':
                    c = colors_p[i_p % len(colors_p)]
                    ls = '-'
                    lbl = f'p₀={p0:.3g} MPa'
                elif mode == 'fix_p0':
                    c = colors_T[i_T % len(colors_T)]
                    ls = '-'
                    lbl = f'T={T0:.0f}°C'
                else:
                    c = colors_p[i_p % len(colors_p)]
                    ls = line_styles[i_T % len(line_styles)]
                    lbl = f'T={T0:.0f}°C, p₀={p0:.3g}'

                ax.semilogx(v_arr, data, linestyle=ls, color=c, linewidth=1.5, label=lbl)

        # Overlay tab verification data
        if show_overlay and hasattr(self, 'mu_visc_results') and self.mu_visc_results is not None:
            mvr = self.mu_visc_results
            v_ref = mvr.get('v')
            if v_ref is not None:
                overlay_data = None
                overlay_label = None
                # Tab σ₀ for force overlay (MPa)
                try:
                    tab_sigma0_MPa = float(self.sigma_0_var.get())
                except (ValueError, AttributeError):
                    tab_sigma0_MPa = 0.3

                if data_key in ('mu_visc', 'F_visc'):
                    overlay_data = mvr.get('mu') if branch == 'cold' else mvr.get('mu_hot')
                    if overlay_data is not None and data_key == 'F_visc':
                        overlay_data = overlay_data * tab_sigma0_MPa
                    overlay_label = f'탭 검증 (F_hys, σ₀={tab_sigma0_MPa}MPa)' if is_force else 'mu_visc 탭 (mu_hys)'
                elif data_key == 'A_A0':
                    overlay_data = mvr.get('A_A0_cold') if branch == 'cold' else mvr.get('A_A0_hot')
                    overlay_label = 'mu_visc 탭 (A/A0)'
                elif data_key in ('mu_total', 'F_total'):
                    mu_v = mvr.get('mu') if branch == 'cold' else mvr.get('mu_hot')
                    mar = getattr(self, 'mu_adh_results', None)
                    mu_a = mar.get('mu_adh') if mar else None
                    if mu_v is not None and mu_a is not None and len(mu_v) == len(mu_a):
                        overlay_data = mu_v + mu_a
                        if is_force:
                            overlay_data = overlay_data * tab_sigma0_MPa
                        overlay_label = f'탭 검증 (F_total, σ₀={tab_sigma0_MPa}MPa)' if is_force else 'mu_visc+mu_adh 탭 (total)'
                elif data_key in ('mu_adh', 'F_adh'):
                    mar = getattr(self, 'mu_adh_results', None)
                    if mar:
                        overlay_data = mar.get('mu_adh')
                        if overlay_data is not None and is_force:
                            overlay_data = overlay_data * tab_sigma0_MPa
                        overlay_label = f'탭 검증 (F_adh, σ₀={tab_sigma0_MPa}MPa)' if is_force else 'mu_adh 탭'
                elif data_key == 'tau_f':
                    mar = getattr(self, 'mu_adh_results', None)
                    if mar and mar.get('tau_f') is not None:
                        overlay_data = mar['tau_f'] / 1e6
                        overlay_label = 'mu_adh 탭 (tau_f)'

                if overlay_data is not None and overlay_label is not None:
                    ax.semilogx(v_ref, overlay_data, 'ko-', linewidth=2.5, alpha=0.6,
                                markersize=3, label=overlay_label, zorder=10)

        # Axis labels and title
        y_labels = {'mu_total': r'$\mu_{total}$', 'A_A0': 'A/A₀', 'tau_f': r'$\tau_s$ (MPa)',
                    'mu_visc': r'$\mu_{hysteresis}$', 'mu_adh': r'$\mu_{adhesion}$',
                    'F_visc': r'$F_{hys}$ (MPa)', 'F_adh': r'$F_{adh}$ (MPa)',
                    'F_total': r'$F_{total}$ (MPa)'}
        mode_desc = {'fix_T': f'T={T_arr[T_indices[0]]:.0f}°C 고정',
                     'fix_p0': f'p₀={p0_arr[p0_indices[0]]:.3g} MPa 고정',
                     'all': '전체'}
        ax.set_xlabel('Velocity v (m/s)', fontsize=11)
        ax.set_ylabel(y_labels.get(data_key, data_key), fontsize=11)
        ax.set_title(f'{y_labels.get(data_key, data_key)}  [{branch.upper()}]  —  {mode_desc.get(mode, "")}',
                     fontweight='bold', fontsize=12)
        ax.grid(True, alpha=0.3)
        ax.legend(fontsize=8, loc='best')

        self.canvas_fm_graph.draw_idle()

    def _apply_fm_p0_preset(self):
        """Apply selected pressure preset to the array field."""
        preset = self.fm_p0_preset_var.get()
        if preset in self._fm_p0_presets:
            self.fm_p0_array_var.set(self._fm_p0_presets[preset])

    def _test_run_pipeline(self):
        """시험 Run: 내장 데이터를 사용하여 전체 파이프라인을 자동 실행.

        1) PSD 로드 → 확정
        2) 마스터 커브 로드 → aT 로드 → 스무딩 → 확정
        3) IDIADA 프리셋 로드 → G(q,v) 계산
        4) Strain Sweep 로드 → f,g 계산 → 외삽 → Persson avg f,g
        5) 비선형 f,g 보정 ON, Flash Temperature ON
        6) mu_visc 계산
        7) mu_dry 로드 → 자동 피팅 → 피팅 완료
        8) Cold & Hot Branch 계산
        """
        import time

        steps = [
            "1/8  PSD 로드 (IDIADA_PSD.txt)",
            "2/8  마스터 커브 & aT 로드",
            "3/8  G(q,v) 계산",
            "4/8  Strain Sweep → f,g 계산",
            "5/8  mu_visc 계산",
            "6/8  mu_adh 자동 피팅",
            "7/8  mu_adh 피팅 완료",
            "8/8  Cold & Hot Branch 계산",
        ]

        try:
            # ── Step 1: PSD 로드 & 확정 ──
            self.status_var.set(steps[0])
            self.root.update()

            self.preset_psd_var.set("IDIADA_PSD.txt")
            self._load_preset_psd()
            self.root.update()

            self._apply_profile_psd_to_tab3()
            self.root.update()
            print("[TestRun] Step 1 완료: PSD 로드 & 확정")

            # ── Step 2: 마스터 커브 & aT 로드 → 스무딩 → 확정 ──
            self.status_var.set(steps[1])
            self.root.update()

            self.preset_mc_var.set("S100_master_final.txt")
            self._load_preset_mastercurve()
            self.root.update()

            self.preset_aT_var.set("S100_at_final.txt")
            self._load_preset_aT()
            self.root.update()

            self._apply_smoothing_to_persson()
            self.root.update()

            self._use_persson_master_curve_for_calc()
            self.root.update()
            print("[TestRun] Step 2 완료: 마스터 커브 & aT 확정")

            # ── Step 3: IDIADA 프리셋 로드 → G(q,v) 계산 ──
            self.status_var.set(steps[2])
            self.root.update()

            self.surface_q1_var.set("IDIADA")
            self._load_preset_surface_q1()
            self.root.update()

            self._run_calculation()
            self.root.update()
            print("[TestRun] Step 3 완료: G(q,v) 계산")

            # ── Step 4: Strain Sweep → f,g 계산 → 외삽 → Persson avg ──
            self.status_var.set(steps[3])
            self.root.update()

            self.preset_ss_var.set("S100_Y1_final.txt")
            self._load_preset_strain_sweep()
            self.root.update()

            self._compute_fg_curves()
            self.root.update()

            self._extrapolate_fg_curves()
            self.root.update()

            self._persson_average_fg()
            self.root.update()
            print("[TestRun] Step 4 완료: f,g 계산 & Persson 평균")

            # ── Step 5: 비선형 보정 ON, Flash ON → mu_visc 계산 ──
            self.status_var.set(steps[4])
            self.root.update()

            self.use_fg_correction_var.set(True)
            self.use_flash_temp_var.set(True)

            self._calculate_mu_visc()
            self.root.update()
            print("[TestRun] Step 5 완료: mu_visc 계산")

            # ── Step 6: mu_dry 프리셋 로드 → 자동 피팅 ──
            self.status_var.set(steps[5])
            self.root.update()

            self.preset_mu_dry_var.set("S100_total_mu_exp.txt")
            self._load_preset_mu_dry()
            self.root.update()

            self._run_auto_fit_mu_dry()
            self.root.update()
            print("[TestRun] Step 6 완료: mu_adh 자동 피팅")

            # ── Step 7: mu_adh 피팅 완료 ──
            self.status_var.set(steps[6])
            self.root.update()

            self._complete_adh_fitting()
            self.root.update()
            print("[TestRun] Step 7 완료: mu_adh 피팅 확정")

            # ── Step 8: Cold & Hot Branch 계산 ──
            self.status_var.set(steps[7])
            self.root.update()

            self._calculate_cold_hot_branch()
            self.root.update()
            print("[TestRun] Step 8 완료: Cold & Hot Branch")

            self.status_var.set("시험 Run 완료 — Friction Map 생성 가능")
            self._show_status(
                "시험 Run 파이프라인 완료!\n\n"
                "모든 전처리가 완료되었습니다.\n"
                "'Friction Map 생성' 버튼을 눌러 마찰맵을 생성하세요.", 'success')

        except Exception as e:
            import traceback
            traceback.print_exc()
            self.status_var.set(f"시험 Run 실패: {e}")
            self._show_status(f"시험 Run 중 오류 발생:\n{str(e)}", 'error')

    def _calculate_friction_map(self):
        """Generate 3D friction map LUT (T0 × p0 × v) for Cold and Hot branches."""
        try:
            import time as _time
            t_start = _time.time()

            # ── Validate prerequisites ──
            if self.psd_model is None:
                self._show_status("PSD 데이터가 없습니다. Tab 0에서 PSD를 확정하세요.", 'warning')
                return
            if self.material is None:
                self._show_status("마스터 커브 데이터가 없습니다. Tab 1에서 확정하세요.", 'warning')
                return
            if not self.results or '2d_results' not in self.results:
                self._show_status("G(q,v) 데이터가 없습니다. 먼저 G(q,v) 계산을 실행하세요.", 'warning')
                return
            if not hasattr(self, 'mu_adh_results') or self.mu_adh_results is None:
                self._show_status("μ_adh 결과가 없습니다. μ_adh 탭에서 먼저 계산하세요.", 'warning')
                return

            has_aT = (hasattr(self, 'persson_aT_interp') and self.persson_aT_interp is not None
                      and hasattr(self, 'persson_master_curve') and self.persson_master_curve is not None)
            if not has_aT:
                self._show_status("aT 시프트 팩터가 필요합니다. Tab 1에서 aT를 로드하세요.", 'warning')
                return

            self.fm_progress_var.set(0)
            self.fm_status_label.config(text="Sweep 격자 생성 중...")
            self.root.update()

            # ── Parse sweep grids ──
            T_start = float(self.fm_T_start_var.get())
            T_end = float(self.fm_T_end_var.get())
            T_step = float(self.fm_T_step_var.get())
            T_array = np.arange(T_start, T_end + T_step * 0.5, T_step)

            p0_str = self.fm_p0_array_var.get()
            p0_array_MPa = np.array([float(x.strip()) for x in p0_str.split(',')])
            p0_array_Pa = p0_array_MPa * 1e6

            v_log_start = float(self.fm_v_log_start_var.get())
            v_log_end = float(self.fm_v_log_end_var.get())
            v_npts = int(self.fm_v_npts_var.get())
            v_array = np.logspace(v_log_start, v_log_end, v_npts)

            n_T = len(T_array)
            n_p = len(p0_array_Pa)
            n_v = len(v_array)
            total_cells = n_T * n_p
            print(f"[FrictionMap] Grid: {n_T} temps × {n_p} pressures × {n_v} velocities = {n_T*n_p*n_v} cells")

            # ── Allocate LUT arrays ──
            LUT_cold = np.zeros((n_T, n_p, n_v))
            LUT_hot = np.zeros((n_T, n_p, n_v))
            LUT_mu_visc_cold = np.zeros((n_T, n_p, n_v))
            LUT_mu_visc_hot = np.zeros((n_T, n_p, n_v))
            LUT_mu_adh_cold = np.zeros((n_T, n_p, n_v))
            LUT_mu_adh_hot = np.zeros((n_T, n_p, n_v))
            LUT_A_A0_cold = np.zeros((n_T, n_p, n_v))
            LUT_A_A0_hot = np.zeros((n_T, n_p, n_v))
            LUT_tau_f_cold = np.zeros((n_T, n_p, n_v))
            LUT_tau_f_hot = np.zeros((n_T, n_p, n_v))

            # ── Get shared parameters from mu_visc tab ──
            from persson_model.core.friction import FrictionCalculator
            from persson_model.core.flash_temperature import FlashTemperatureCalculator
            from scipy.interpolate import interp1d as interp1d_fm
            from scipy.special import erf as erf_fm

            results_2d = self.results['2d_results']
            q_full = results_2d['q']

            # ── mu_visc 탭과 동일한 q 그리드 & 적분 해상도 사용 ──
            q = q_full.copy()
            n_q = len(q)
            C_q = self.psd_model(q)
            print(f"[FrictionMap] mu_visc 탭과 동일 해상도: n_q={n_q}")

            # Read mu_visc tab settings (동일 파라미터)
            poisson = float(self.poisson_var.get())
            gamma = float(self.gamma_var.get())
            n_phi = int(self.n_phi_var.get())  # mu_visc 탭과 동일
            use_fg = self.use_fg_correction_var.get()

            sq_method = getattr(self, 'sq_method_var', None)
            p_exponent = 1 if (sq_method and sq_method.get() == "P1") else 2

            # Strain settings
            strain_est_method = self.strain_est_method_var.get()
            fixed_strain = float(self.fixed_strain_var.get()) / 100.0

            # Adhesion parameters (from mu_adh tab, cold-fitted)
            adh_params = self.mu_adh_results['params']
            tau_f0 = adh_params['tau_f0']       # Pa
            v0_star = adh_params['v0_star']     # m/s
            c_adh = adh_params['c']
            epsilon_adh = adh_params['epsilon'] # eV
            T_ref_adh = adh_params['T_ref']     # K
            k_B = 8.6173e-5                     # eV/K

            # Flash temperature settings
            use_flash = self.use_flash_temp_var.get()
            flash_rho = float(self.flash_rho_var.get())
            flash_Cv = float(self.flash_Cv_var.get())
            flash_kappa = float(self.flash_kappa_var.get())
            flash_d = float(self.flash_d_macro_var.get()) / 1000.0  # mm → m
            flash_h_layer = 1.0 / q[-1]

            try:
                Amin_flash = float(self.flash_Amin_var.get())
                Amax_flash = float(self.flash_Amax_var.get())
            except (ValueError, AttributeError):
                Amin_flash = 0.03
                Amax_flash = 0.6

            flash_calc = FlashTemperatureCalculator(
                rho=flash_rho, C_v=flash_Cv,
                kappa_th=flash_kappa, d_macro=flash_d,
                h_layer=flash_h_layer
            )

            # Normalization factor
            try:
                norm_factor = float(self.g_norm_factor_var.get())
            except (ValueError, AttributeError):
                norm_factor = 1.5625

            # Prepare RMS strain interpolator for nonlinear correction
            rms_strain_interp_fm = None
            if use_fg:
                if strain_est_method == 'rms_slope' and self.rms_slope_calculator is not None:
                    from scipy.interpolate import interp1d as interp1d_strain
                    rms_q = self.rms_slope_profiles['q']
                    rms_strain = self.rms_slope_profiles['strain']
                    log_q_s = np.log10(rms_q)
                    log_strain_s = np.log10(np.maximum(rms_strain, 1e-10))
                    rms_strain_interp_fm = interp1d_strain(
                        log_q_s, log_strain_s, kind='linear',
                        bounds_error=False, fill_value='extrapolate')
                print(f"[FrictionMap] 비선형 보정 활성화 (method={strain_est_method})")

            # ── Helper: create WLF-shifted modulus functions for a given temperature ──
            from persson_model.core.g_calculator import GCalculator as GCalc_FM

            mc_data = self.persson_master_curve
            omega_ref = mc_data['omega'].copy()
            E_storage_ref = mc_data['E_storage'].copy()
            E_loss_ref = mc_data['E_loss'].copy()

            log_omega_master = np.log10(np.maximum(omega_ref, 1e-30))
            log_E_storage_master = np.log10(np.maximum(E_storage_ref, 1e-30))
            log_E_loss_master = np.log10(np.maximum(E_loss_ref, 1e-30))

            E_storage_interp_fm = interp1d_fm(
                log_omega_master, log_E_storage_master,
                kind='linear', bounds_error=False,
                fill_value=(log_E_storage_master[0], log_E_storage_master[-1])
            )
            E_loss_interp_fm = interp1d_fm(
                log_omega_master, log_E_loss_master,
                kind='linear', bounds_error=False,
                fill_value=(log_E_loss_master[0], log_E_loss_master[-1])
            )

            q_min_val = float(self.q_min_var.get())

            def _make_modulus_funcs(aT_shift):
                """Create complex, storage, and loss modulus functions for a given aT."""
                def modulus_func(omega):
                    omega = np.atleast_1d(omega)
                    omega_shifted = np.maximum(omega * aT_shift, 1e-30)
                    log_w = np.log10(omega_shifted)
                    Ep = 10.0 ** E_storage_interp_fm(log_w)
                    Epp = 10.0 ** E_loss_interp_fm(log_w)
                    result = Ep + 1j * Epp
                    return result[0] if result.size == 1 else result

                def storage_func(omega):
                    omega = np.atleast_1d(omega)
                    omega_shifted = np.maximum(omega * aT_shift, 1e-30)
                    log_w = np.log10(omega_shifted)
                    Ep = 10.0 ** E_storage_interp_fm(log_w)
                    return Ep[0] if Ep.size == 1 else Ep

                def loss_func(omega):
                    omega = np.atleast_1d(omega)
                    omega_shifted = np.maximum(omega * aT_shift, 1e-30)
                    log_w = np.log10(omega_shifted)
                    Epp = 10.0 ** E_loss_interp_fm(log_w)
                    return Epp[0] if Epp.size == 1 else Epp

                return modulus_func, storage_func, loss_func

            def _compute_mu_visc_at_T_p0(aT_val, p0_val, v_arr, apply_fg=False):
                """Compute G(q,v), P(q), mu_visc using GCalculator + FrictionCalculator.

                Returns (mu_visc_array, A_A0_array).
                """
                mod_func, stor_func, loss_func = _make_modulus_funcs(aT_val)

                # Create GCalculator with exact same settings as mu_visc tab
                g_calc = GCalc_FM(
                    psd_func=self.psd_model,
                    modulus_func=mod_func,
                    sigma_0=p0_val,
                    velocity=v_arr[0],
                    poisson_ratio=poisson,
                    n_angle_points=n_phi,
                    storage_modulus_func=stor_func,
                    loss_modulus_func=loss_func,
                )
                g_calc.PSD_NORMALIZATION_FACTOR = norm_factor
                print(f"    [_compute] p0={p0_val/1e6:.4f} MPa, "
                      f"g_calc.prefactor={g_calc.prefactor:.6e}, "
                      f"g_calc.sigma_0={g_calc.sigma_0:.2e}")

                # Apply nonlinear correction if enabled
                if apply_fg and use_fg:
                    if hasattr(self, 'f_interpolator') and self.f_interpolator is not None \
                       and hasattr(self, 'g_interpolator') and self.g_interpolator is not None:
                        g_calc.set_nonlinear_correction(
                            f_interpolator=self.f_interpolator,
                            g_interpolator=self.g_interpolator,
                            strain_array=strain_for_G,
                            strain_q_array=q
                        )

                # Calculate G(q,v) for all velocities
                n_v_local = len(v_arr)
                G_matrix_local = np.zeros((n_q, n_v_local))
                P_matrix_local = np.zeros((n_q, n_v_local))

                for j, v_j in enumerate(v_arr):
                    g_calc.velocity = v_j
                    res = g_calc.calculate_G_with_details(q, q_min=q_min_val)
                    G_matrix_local[:, j] = res['G']
                    P_matrix_local[:, j] = res['contact_area_ratio']

                # Create FrictionCalculator (same as mu_visc tab)
                # loss_modulus_func for FrictionCalculator: takes (omega, T) but T is
                # already baked into the WLF shift, so ignore T parameter
                def loss_mod_for_friction(omega, T):
                    return loss_func(omega)

                g_interp_local = self.g_interpolator if use_fg else None

                fric_calc = FrictionCalculator(
                    psd_func=self.psd_model,
                    loss_modulus_func=loss_mod_for_friction,
                    sigma_0=p0_val,
                    velocity=v_arr[0],
                    temperature=0.0,  # T already in WLF shift
                    poisson_ratio=poisson,
                    gamma=gamma,
                    n_angle_points=n_phi,
                    g_interpolator=g_interp_local,
                    strain_estimate=fixed_strain,
                    p_exponent=p_exponent
                )

                # Use strain estimator if nonlinear correction is enabled
                strain_est_func = None
                if use_fg and g_interp_local is not None:
                    def strain_est_func(q_arr, G_arr, velocity):
                        n_s = len(q_arr)
                        if strain_est_method == 'rms_slope' and rms_strain_interp_fm is not None:
                            s_arr = np.zeros(n_s)
                            for i_s, qi_s in enumerate(q_arr):
                                try:
                                    s_arr[i_s] = 10 ** rms_strain_interp_fm(np.log10(qi_s))
                                except:
                                    s_arr[i_s] = fixed_strain
                            return np.clip(s_arr, 0.0, 1.0)
                        else:
                            return np.full(n_s, fixed_strain)

                mu_array, details = fric_calc.calculate_mu_visc_multi_velocity(
                    q, G_matrix_local, v_arr, C_q,
                    strain_estimator=strain_est_func
                )

                # Extract A/A0 = P(q_max) for each velocity
                A_A0_arr = np.zeros(n_v_local)
                for j in range(n_v_local):
                    P_j = details['details'][j]['P']
                    A_A0_arr[j] = P_j[-1]

                # Diagnostic: G, erf argument, P, mu at each pressure
                G_max = G_matrix_local.max()
                G_at_qmax_mid = G_matrix_local[-1, n_v_local // 2]  # G(q_max) at mid velocity
                erf_arg = 1.0 / (2.0 * np.sqrt(G_at_qmax_mid)) if G_at_qmax_mid > 0 else float('inf')
                print(f"    [_compute] p0={p0_val/1e6:.4f} MPa → "
                      f"G(q_max,v_mid)={G_at_qmax_mid:.4e}, "
                      f"erf_arg={erf_arg:.6f}, "
                      f"A/A0: {A_A0_arr.min():.6f}~{A_A0_arr.max():.6f}, "
                      f"mu_visc: {mu_array.min():.6f}~{mu_array.max():.6f}")
                if erf_arg < 0.5:
                    print(f"    ⚠ erf_arg={erf_arg:.6f} < 0.5 → erf 선형 근사 영역 "
                          f"(A/A0 ∝ p0, μ_adh 하중 무관해짐)")

                return mu_array, A_A0_arr

            # Pre-compute strain array for G nonlinear correction
            strain_for_G = np.full(n_q, fixed_strain)
            if use_fg and (hasattr(self, 'f_interpolator') and self.f_interpolator is not None):
                if strain_est_method == 'rms_slope' and rms_strain_interp_fm is not None:
                    for i_q in range(n_q):
                        try:
                            strain_for_G[i_q] = np.clip(
                                10 ** rms_strain_interp_fm(np.log10(q[i_q])), 0.0, 1.0)
                        except:
                            strain_for_G[i_q] = fixed_strain

            # ── Main triple loop ──
            cell_count = 0
            for i_T, T0 in enumerate(T_array):
                # WLF shift at T0
                log_aT_T0 = float(self.persson_aT_interp(T0))
                aT_T0 = 10 ** log_aT_T0

                # Arrhenius shift for adhesion at T0
                T0_K = T0 + 273.15
                aT_prime_T0 = np.exp((epsilon_adh / k_B) * (1.0 / T0_K - 1.0 / T_ref_adh))

                for i_p, p0_Pa in enumerate(p0_array_Pa):
                    # ── Cold branch: use GCalculator + FrictionCalculator ──
                    mu_visc_cold, A_A0_cold = _compute_mu_visc_at_T_p0(
                        aT_T0, p0_Pa, v_array, apply_fg=use_fg)

                    # ── Cold adhesion: τ_f(v × aT') / p0 × A/A0_cold ──
                    v_eff_cold = v_array * aT_prime_T0
                    log_ratio_cold = np.log10(np.maximum(v_eff_cold, 1e-30) / v0_star)
                    tau_f_cold = tau_f0 * np.exp(-c_adh * log_ratio_cold**2)
                    mu_adh_cold = (tau_f_cold / p0_Pa) * A_A0_cold
                    mu_cold_total = mu_visc_cold + mu_adh_cold

                    # ── Diagnostic output for per-pressure verification ──
                    print(f"  [T={T0:.0f}°C, p0={p0_Pa/1e6:.3f}MPa] "
                          f"mu_visc: {mu_visc_cold.min():.6f}~{mu_visc_cold.max():.6f}, "
                          f"mu_adh: {mu_adh_cold.min():.6f}~{mu_adh_cold.max():.6f}, "
                          f"mu_total: {mu_cold_total.min():.6f}~{mu_cold_total.max():.6f}, "
                          f"A/A0: {A_A0_cold.min():.6f}~{A_A0_cold.max():.6f}, "
                          f"prefactor=1/((1-v^2)*s0)={1.0/((1-poisson**2)*p0_Pa):.6e}")

                    LUT_mu_visc_cold[i_T, i_p, :] = mu_visc_cold
                    LUT_mu_adh_cold[i_T, i_p, :] = mu_adh_cold
                    LUT_A_A0_cold[i_T, i_p, :] = A_A0_cold
                    LUT_tau_f_cold[i_T, i_p, :] = tau_f_cold
                    LUT_cold[i_T, i_p, :] = mu_cold_total

                    # ── Hot branch: per-q flash temperature (Persson Full) ──
                    if use_flash:
                        from scipy.integrate import simpson as simpson_fm
                        from scipy.interpolate import interp1d as interp1d_fm_hot

                        mu_visc_hot = np.zeros(n_v)
                        A_A0_hot = np.zeros(n_v)
                        delta_T_arr = np.zeros(n_v)

                        # Fine q grid for per-q flash integration (delnn from GUI)
                        try:
                            delnn_fm = float(self.flash_delnn_var.get())
                        except (ValueError, AttributeError):
                            delnn_fm = 0.05
                        delnn_fm = max(delnn_fm, 0.001)
                        log_q_min_fm = np.log10(q[0])
                        log_q_max_fm = np.log10(q[-1])
                        n_q_hot_fm = max(int(np.ceil((log_q_max_fm - log_q_min_fm) / delnn_fm)) + 1, n_q)
                        q_hot_fm = np.logspace(log_q_min_fm, log_q_max_fm, n_q_hot_fm)
                        C_q_hot_fm = self.psd_model(q_hot_fm)

                        # Angle arrays for integration
                        phi_fm = np.linspace(0, np.pi / 2, n_phi)
                        cos_phi_fm = np.cos(phi_fm)
                        prefactor_fm = 1.0 / ((1 - poisson**2) * p0_Pa)

                        # Strain array on fine grid for nonlinear correction
                        strain_arr_hot_fm = None
                        if use_fg and rms_strain_interp_fm is not None:
                            strain_arr_hot_fm = np.zeros(n_q_hot_fm)
                            for i_s in range(n_q_hot_fm):
                                try:
                                    strain_arr_hot_fm[i_s] = np.clip(
                                        10 ** rms_strain_interp_fm(np.log10(q_hot_fm[i_s])), 0.0, 1.0)
                                except Exception:
                                    strain_arr_hot_fm[i_s] = fixed_strain
                        elif use_fg:
                            strain_arr_hot_fm = np.full(n_q_hot_fm, fixed_strain)

                        g_interp_fm = self.g_interpolator if use_fg else None

                        for j_v, v_j in enumerate(v_array):
                            # Per-q forward pass with temperature accumulation
                            G_hot_arr = np.zeros(n_q_hot_fm)
                            P_hot_arr = np.ones(n_q_hot_fm)
                            S_hot_arr = np.ones(n_q_hot_fm)
                            integrand_hot = np.zeros(n_q_hot_fm)
                            delta_T_per_q = np.zeros(n_q_hot_fm)
                            T_acc = T0
                            prev_G_int = 0.0
                            prev_mu_int = 0.0
                            mu_cumul = 0.0

                            for i in range(n_q_hot_fm):
                                # WLF shift at accumulated temperature
                                log_aT_i = float(self.persson_aT_interp(T_acc))
                                aT_i = 10 ** log_aT_i

                                omega_phys = q_hot_fm[i] * v_j * cos_phi_fm
                                omega_eff = np.maximum(omega_phys * aT_i, 1e-30)
                                log_omega_eff = np.log10(omega_eff)

                                log_Ep = E_storage_interp_fm(log_omega_eff)
                                log_Epp = E_loss_interp_fm(log_omega_eff)
                                Ep_vals = 10.0 ** np.clip(log_Ep, 4.0, None)
                                Epp_vals = 10.0 ** np.clip(log_Epp, 3.0, None)

                                # Nonlinear correction
                                if use_fg and strain_arr_hot_fm is not None:
                                    s_i = float(strain_arr_hot_fm[i]) if i < len(strain_arr_hot_fm) else fixed_strain
                                    s_i = np.clip(s_i, 0.0, 1.0)
                                    if self.f_interpolator is not None:
                                        f_val = float(self.f_interpolator(s_i))
                                        if np.isfinite(f_val):
                                            Ep_vals = Ep_vals * np.clip(f_val, 0.01, 1.0)
                                    if g_interp_fm is not None:
                                        g_val = float(g_interp_fm(s_i))
                                        if np.isfinite(g_val):
                                            Epp_vals = Epp_vals * max(g_val, 0.01)

                                # G integrand: |E*|²
                                E_star_sq = Ep_vals**2 + Epp_vals**2
                                G_int_phi = E_star_sq * prefactor_fm**2
                                if n_phi >= 3:
                                    G_angle_i = 4.0 * simpson_fm(G_int_phi, x=phi_fm)
                                else:
                                    G_angle_i = 4.0 * np.trapezoid(G_int_phi, phi_fm)

                                G_full_i = q_hot_fm[i]**3 * C_q_hot_fm[i] * G_angle_i

                                # Cumulative G (trapezoidal)
                                if i > 0:
                                    dq = q_hot_fm[i] - q_hot_fm[i - 1]
                                    delta_G = 0.5 * (prev_G_int + G_full_i) * dq
                                    G_hot_arr[i] = G_hot_arr[i - 1] + delta_G / (8.0 * norm_factor)
                                prev_G_int = G_full_i

                                # P(q) = erf(1/(2√G))
                                if G_hot_arr[i] > 1e-10:
                                    arg = min(1.0 / (2.0 * np.sqrt(G_hot_arr[i])), 10.0)
                                    P_hot_arr[i] = float(erf_fm(arg))
                                else:
                                    P_hot_arr[i] = 1.0

                                # S(q)
                                S_hot_arr[i] = gamma + (1 - gamma) * P_hot_arr[i] ** p_exponent

                                # μ integrand
                                mu_phi_int = cos_phi_fm * Epp_vals * prefactor_fm
                                if n_phi >= 3:
                                    mu_angle_i = 4.0 * simpson_fm(mu_phi_int, x=phi_fm)
                                else:
                                    mu_angle_i = 4.0 * np.trapezoid(mu_phi_int, phi_fm)

                                integrand_hot[i] = q_hot_fm[i]**3 * C_q_hot_fm[i] * P_hot_arr[i] * S_hot_arr[i] * mu_angle_i

                                # Per-q ΔT (Persson Full per-scale diffusion)
                                delta_mu_i = 0.0
                                if i > 0:
                                    dq = q_hot_fm[i] - q_hot_fm[i - 1]
                                    delta_mu_i = 0.5 * 0.5 * (prev_mu_int + integrand_hot[i]) * dq
                                    mu_cumul += delta_mu_i

                                d_i = np.pi / q_hot_fm[i]
                                Jd_i = v_j * d_i / flash_calc.D_th
                                Jh_i = flash_calc.peclet_number_h(v_j)
                                dq_dot_i = delta_mu_i * p0_Pa * v_j / max(P_hot_arr[i], 1e-6)
                                if dq_dot_i > 0 and np.isfinite(dq_dot_i):
                                    dT_i = (dq_dot_i * d_i) / (4.0 * flash_calc.kappa_th) / np.sqrt(
                                        1.0 + (np.pi / 32.0) * Jd_i + (Jh_i**2) / 4.0)
                                else:
                                    dT_i = 0.0

                                if i == 0:
                                    delta_T_per_q[i] = 0.0
                                else:
                                    delta_T_per_q[i] = delta_T_per_q[i - 1] + dT_i
                                T_acc = T0 + delta_T_per_q[i]

                                prev_mu_int = integrand_hot[i]

                            # Integrate μ over q (fine grid)
                            if n_q_hot_fm >= 3:
                                mu_visc_hot[j_v] = 0.5 * simpson_fm(integrand_hot, x=q_hot_fm)
                            else:
                                mu_visc_hot[j_v] = 0.5 * np.trapezoid(integrand_hot, q_hot_fm)

                            A_A0_hot[j_v] = P_hot_arr[-1]
                            delta_T_arr[j_v] = delta_T_per_q[-1]

                        # Hot adhesion with per-velocity Arrhenius shift at T_hot
                        T_hot_arr = T0 + delta_T_arr
                        T_hot_K = T_hot_arr + 273.15
                        aT_prime_hot = np.exp((epsilon_adh / k_B) * (1.0 / T_hot_K - 1.0 / T_ref_adh))
                        v_eff_hot = v_array * aT_prime_hot
                        log_ratio_hot = np.log10(np.maximum(v_eff_hot, 1e-30) / v0_star)
                        tau_f_hot = tau_f0 * np.exp(-c_adh * log_ratio_hot**2)
                        mu_adh_hot = (tau_f_hot / p0_Pa) * A_A0_hot
                        mu_hot_total = mu_visc_hot + mu_adh_hot

                        LUT_mu_visc_hot[i_T, i_p, :] = mu_visc_hot
                        LUT_mu_adh_hot[i_T, i_p, :] = mu_adh_hot
                        LUT_A_A0_hot[i_T, i_p, :] = A_A0_hot
                        LUT_tau_f_hot[i_T, i_p, :] = tau_f_hot
                        LUT_hot[i_T, i_p, :] = mu_hot_total
                    else:
                        # No flash: hot = cold
                        LUT_mu_visc_hot[i_T, i_p, :] = mu_visc_cold
                        LUT_mu_adh_hot[i_T, i_p, :] = mu_adh_cold
                        LUT_A_A0_hot[i_T, i_p, :] = A_A0_cold
                        LUT_tau_f_hot[i_T, i_p, :] = tau_f_cold
                        LUT_hot[i_T, i_p, :] = mu_cold_total

                    cell_count += 1
                    progress = int(cell_count / total_cells * 90)
                    self.fm_progress_var.set(progress)
                    self.fm_status_label.config(
                        text=f"T={T0:.0f}°C, p0={p0_Pa/1e6:.2f} MPa ({cell_count}/{total_cells})")
                    self.root.update()

            # ── Store results ──
            self.friction_map_results = {
                'T_array': T_array,
                'p0_array_MPa': p0_array_MPa,
                'p0_array_Pa': p0_array_Pa,
                'v_array': v_array,
                'LUT_cold': LUT_cold,
                'LUT_hot': LUT_hot,
                'LUT_mu_visc_cold': LUT_mu_visc_cold,
                'LUT_mu_visc_hot': LUT_mu_visc_hot,
                'LUT_mu_adh_cold': LUT_mu_adh_cold,
                'LUT_mu_adh_hot': LUT_mu_adh_hot,
                'LUT_A_A0_cold': LUT_A_A0_cold,
                'LUT_A_A0_hot': LUT_A_A0_hot,
                'LUT_tau_f_cold': LUT_tau_f_cold,
                'LUT_tau_f_hot': LUT_tau_f_hot,
                'use_flash': use_flash,
            }

            elapsed = _time.time() - t_start
            self.fm_progress_var.set(95)
            self.fm_status_label.config(text="플롯 생성 중...")
            self.root.update()

            # ── Plot ──
            self._plot_friction_map()
            self._update_fm_graph()

            # ── Result text ──
            self._update_friction_map_text(elapsed)

            # ── Update export combo boxes ──
            try:
                self.fm_export_T_combo['values'] = [f"{t:.0f}" for t in T_array]
                self.fm_export_p0_combo['values'] = [f"{p:.4g}" for p in p0_array_MPa]
                if len(T_array) > 0:
                    self.fm_export_T_var.set(f"{T_array[len(T_array)//2]:.0f}")
                if len(p0_array_MPa) > 0:
                    self.fm_export_p0_var.set(f"{p0_array_MPa[len(p0_array_MPa)//2]:.4g}")
            except Exception:
                pass

            self.fm_progress_var.set(100)
            self.fm_status_label.config(text=f"완료 ({elapsed:.1f}s)")
            self._show_status(
                f"Friction Map 생성 완료\n"
                f"Grid: {n_T}×{n_p}×{n_v} = {n_T*n_p*n_v} cells\n"
                f"소요 시간: {elapsed:.1f}s", 'success')

        except Exception as e:
            import traceback
            traceback.print_exc()
            self.fm_status_label.config(text=f"오류: {str(e)}")
            self._show_status(f"Friction Map 생성 실패:\n{str(e)}", 'error')

    def _plot_friction_map(self):
        """Plot 3D friction map surfaces for all pressures (Cold & Hot)."""
        r = self.friction_map_results
        if r is None:
            return

        right_frame = self.friction_map_right
        if right_frame is None:
            return

        # Reset data var to default
        self._fm_3d_data_var.set("mu_total")
        self._replot_friction_map_3d()

    def _replot_friction_map_3d(self):
        """Replot 3D surfaces based on selected data type with scroll support."""
        from matplotlib.figure import Figure
        from matplotlib.backends.backend_tkagg import FigureCanvasTkAgg

        r = self.friction_map_results
        if r is None:
            return

        right_frame = self.friction_map_right
        # Destroy only the plot area (preserve toolbar rows = first 2 children)
        children = right_frame.winfo_children()
        for w in children[2:]:
            w.destroy()

        data_type = self._fm_3d_data_var.get()
        T_arr = r['T_array']
        p0_arr = r['p0_array_MPa']
        v_arr = r['v_array']
        log_v = np.log10(v_arr)
        n_p = len(p0_arr)
        has_hot = r.get('use_flash', False)

        # Axis direction settings
        v_asc = self._fm_3d_v_dir.get() == "asc"
        T_asc = self._fm_3d_T_dir.get() == "asc"

        # Determine which LUT to use
        is_force = data_type.startswith('F_')
        if is_force:
            base_key = data_type.replace('F_', '', 1)
        else:
            base_key = data_type

        def _get_Z(branch, i_p):
            suffix = '_cold' if branch == 'cold' else '_hot'
            if base_key in ('mu_total', 'total'):
                lut_key = 'LUT_cold' if branch == 'cold' else 'LUT_hot'
            elif base_key in ('mu_visc', 'visc'):
                lut_key = f'LUT_mu_visc{suffix}'
            elif base_key in ('mu_adh', 'adh'):
                lut_key = f'LUT_mu_adh{suffix}'
            else:
                lut_key = f'LUT_{base_key}{suffix}'
            Z = r.get(lut_key)
            if Z is None:
                return None
            Z_slice = Z[:, i_p, :].copy()
            if data_type == 'tau_f':
                Z_slice = Z_slice / 1e6
            elif is_force:
                Z_slice = Z_slice * p0_arr[i_p]
            return Z_slice

        # Compute global z-limits
        all_cold = [_get_Z('cold', i) for i in range(n_p)]
        all_cold = [z for z in all_cold if z is not None]
        if not all_cold:
            return
        z_min_cold = min(z.min() for z in all_cold)
        z_max_cold = max(z.max() for z in all_cold)
        if has_hot:
            all_hot = [_get_Z('hot', i) for i in range(n_p)]
            all_hot = [z for z in all_hot if z is not None]
            z_min_hot = min(z.min() for z in all_hot) if all_hot else z_min_cold
            z_max_hot = max(z.max() for z in all_hot) if all_hot else z_max_cold
        else:
            z_min_hot, z_max_hot = z_min_cold, z_max_cold

        # Layout
        n_rows = 2 if has_hot else 1
        MAX_COLS = 4
        n_cols = max(n_p, 1)
        if n_cols > MAX_COLS:
            n_groups = int(np.ceil(n_p / MAX_COLS))
            n_cols_eff = MAX_COLS
            n_grid_rows = n_rows * n_groups
        else:
            n_groups = 1
            n_cols_eff = n_cols
            n_grid_rows = n_rows

        # Figure size: width fills panel, height grows with rows for scrolling
        right_frame.update_idletasks()
        avail_w = right_frame.winfo_width()
        toolbar_h = 60  # two toolbar rows
        if avail_w < 200:
            avail_w = 900
        fig_dpi = 100
        fig_w = max(avail_w - 20, 600) / fig_dpi  # -20 for scrollbar
        row_h = 4.5  # inches per subplot row
        fig_h = max(row_h * n_grid_rows, 5)
        fig = Figure(figsize=(fig_w, fig_h), dpi=fig_dpi, facecolor='white')
        fig.subplots_adjust(left=0.04, right=0.97, top=0.92, bottom=0.04,
                            wspace=0.22, hspace=0.35)

        T_mesh, V_mesh = np.meshgrid(T_arr, log_v, indexing='ij')

        use_fine = len(T_arr) >= 2 and len(v_arr) >= 2
        if use_fine:
            from scipy.interpolate import RectBivariateSpline
            T_fine = np.linspace(T_arr[0], T_arr[-1], 25)
            log_v_fine = np.linspace(log_v[0], log_v[-1], 40)
            T_mesh_f, V_mesh_f = np.meshgrid(T_fine, log_v_fine, indexing='ij')

        # z-axis label
        z_labels = {'mu_total': r'$\mu_{total}$', 'mu_visc': r'$\mu_{hys}$',
                     'mu_adh': r'$\mu_{adh}$', 'A_A0': 'A/A₀',
                     'tau_f': r'$\tau_s$ (MPa)',
                     'F_total': r'$F_{total}$ (MPa)', 'F_visc': r'$F_{hys}$ (MPa)',
                     'F_adh': r'$F_{adh}$ (MPa)'}
        z_label = z_labels.get(data_type, data_type)

        # Axis position settings
        v_left = self._fm_3d_v_pos.get() == "left"
        T_left = self._fm_3d_T_pos.get() == "left"

        # Compute azimuth based on axis position (which axis on left/right)
        # In matplotlib 3D: azim controls rotation around z-axis
        # azim=225: x(T) goes right, y(v) goes left
        # azim=315: x(T) goes left, y(v) goes right
        # azim=135: x(T) goes left, y(v) goes left (flipped)
        # azim=45:  x(T) goes right, y(v) goes right (flipped)
        if v_left and not T_left:
            azim = 225  # v on left, T on right (default)
        elif not v_left and T_left:
            azim = 315  # v on right, T on left
        elif T_left and v_left:
            azim = 135
        else:
            azim = 45

        self._fm_3d_axes = []

        def _plot_surface(ax, Z, cmap_name, label, p0, z_lo, z_hi):
            if use_fine:
                try:
                    sp = RectBivariateSpline(T_arr, log_v, Z)
                    Z_f = sp(T_fine, log_v_fine)
                    ax.plot_surface(T_mesh_f, V_mesh_f, Z_f,
                                    cmap=cmap_name, alpha=0.85,
                                    rstride=1, cstride=1,
                                    linewidth=0, antialiased=False,
                                    rasterized=True, vmin=z_lo, vmax=z_hi)
                except Exception:
                    ax.plot_surface(T_mesh, V_mesh, Z,
                                    cmap=cmap_name, alpha=0.85,
                                    rasterized=True, vmin=z_lo, vmax=z_hi)
            else:
                ax.plot_surface(T_mesh, V_mesh, Z,
                                cmap=cmap_name, alpha=0.85,
                                rasterized=True, vmin=z_lo, vmax=z_hi)
            ax.set_zlim(z_lo, z_hi)
            ax.set_xlabel(r'$T_0$ ($^\circ$C)', fontsize=11, labelpad=6)
            ax.set_ylabel(r'$\log_{10}(v)$', fontsize=11, labelpad=6)
            ax.set_zlabel(z_label, fontsize=11, labelpad=6)
            title_color = '#1565C0' if label == 'Cold' else '#C62828'
            ax.set_title(f'{label}  $p_0$={p0:.3g} MPa\n'
                         f'{z_label}: {Z.min():.4f} ~ {Z.max():.4f}',
                         fontsize=11, fontweight='bold', color=title_color)
            ax.view_init(elev=25, azim=azim)
            ax.tick_params(labelsize=9)
            # Axis direction: invert if descending
            if not v_asc:
                ax.invert_yaxis()
            if not T_asc:
                ax.invert_xaxis()

        for i_p, p0 in enumerate(p0_arr):
            group_idx = i_p // MAX_COLS
            col_idx = i_p % MAX_COLS

            cold_row = group_idx * n_rows
            subplot_idx = cold_row * n_cols_eff + col_idx + 1
            ax_cold = fig.add_subplot(n_grid_rows, n_cols_eff, subplot_idx, projection='3d')
            self._fm_3d_axes.append(ax_cold)
            Z_cold = all_cold[i_p]
            _plot_surface(ax_cold, Z_cold, 'viridis', 'Cold', p0, z_min_cold, z_max_cold)

            if has_hot:
                hot_row = cold_row + 1
                subplot_idx_h = hot_row * n_cols_eff + col_idx + 1
                ax_hot = fig.add_subplot(n_grid_rows, n_cols_eff, subplot_idx_h, projection='3d')
                self._fm_3d_axes.append(ax_hot)
                Z_hot = all_hot[i_p]
                _plot_surface(ax_hot, Z_hot, 'inferno', 'Hot', p0, z_min_hot, z_max_hot)

        # Scrollable canvas for the matplotlib figure
        scroll_frame = tk.Frame(right_frame, bg='white')
        scroll_frame.pack(fill=tk.BOTH, expand=True)

        v_scrollbar = ttk.Scrollbar(scroll_frame, orient=tk.VERTICAL)
        v_scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        plot_canvas = tk.Canvas(scroll_frame, yscrollcommand=v_scrollbar.set,
                                bg='white', highlightthickness=0)
        v_scrollbar.config(command=plot_canvas.yview)
        plot_canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        inner_frame = tk.Frame(plot_canvas, bg='white')
        canvas = FigureCanvasTkAgg(fig, master=inner_frame)
        canvas.draw()
        canvas_widget = canvas.get_tk_widget()
        fig_w_px = int(fig_w * fig_dpi)
        fig_h_px = int(fig_h * fig_dpi)
        canvas_widget.config(width=fig_w_px, height=fig_h_px)
        canvas_widget.pack(fill=tk.X)

        win_id = plot_canvas.create_window((0, 0), window=inner_frame, anchor='nw',
                                           width=fig_w_px)

        def _on_configure(event):
            plot_canvas.configure(scrollregion=plot_canvas.bbox('all'))
            # Keep figure width matched to canvas width
            new_w = event.width
            if new_w > 100:
                plot_canvas.itemconfig(win_id, width=new_w)
        plot_canvas.bind('<Configure>', _on_configure)

        # Mousewheel scrolling
        def _on_mousewheel(event):
            if event.delta:
                plot_canvas.yview_scroll(int(-1 * (event.delta / 120)), 'units')
            elif event.num == 4:
                plot_canvas.yview_scroll(-3, 'units')
            elif event.num == 5:
                plot_canvas.yview_scroll(3, 'units')

        def _bind_mw(event):
            plot_canvas.bind_all('<MouseWheel>', _on_mousewheel)
            plot_canvas.bind_all('<Button-4>', _on_mousewheel)
            plot_canvas.bind_all('<Button-5>', _on_mousewheel)

        def _unbind_mw(event):
            plot_canvas.unbind_all('<MouseWheel>')
            plot_canvas.unbind_all('<Button-4>')
            plot_canvas.unbind_all('<Button-5>')

        plot_canvas.bind('<Enter>', _bind_mw)
        plot_canvas.bind('<Leave>', _unbind_mw)

        self._fm_fig = fig
        self._fm_canvas = canvas

    def _update_friction_map_text(self, elapsed):
        """Update the result summary text for Friction Map tab."""
        r = self.friction_map_results
        if r is None:
            return

        T_arr = r['T_array']
        p0_arr = r['p0_array_MPa']
        v_arr = r['v_array']

        lines = [
            "══════════════════════════════════════",
            "   Friction Map (3D LUT) 결과 요약",
            "══════════════════════════════════════",
            "",
            f"Grid: {len(T_arr)} temps x {len(p0_arr)} pressures x {len(v_arr)} velocities",
            f"  T0: {T_arr[0]:.0f} ~ {T_arr[-1]:.0f} C ({len(T_arr)} pts)",
            f"  p0: {p0_arr[0]:.2f} ~ {p0_arr[-1]:.2f} MPa ({len(p0_arr)} pts)",
            f"  v:  {v_arr[0]:.1e} ~ {v_arr[-1]:.1e} m/s ({len(v_arr)} pts)",
            "",
            "── Cold Branch (전체) ──",
            f"  mu_total range: [{r['LUT_cold'].min():.4f}, {r['LUT_cold'].max():.4f}]",
            f"  mu_visc range:  [{r['LUT_mu_visc_cold'].min():.4f}, {r['LUT_mu_visc_cold'].max():.4f}]",
            f"  mu_adh range:   [{r['LUT_mu_adh_cold'].min():.4f}, {r['LUT_mu_adh_cold'].max():.4f}]",
            f"  A/A0 range:    [{r['LUT_A_A0_cold'].min():.6f}, {r['LUT_A_A0_cold'].max():.6f}]",
            "",
            "── Hot Branch (전체) ──",
            f"  mu_total range: [{r['LUT_hot'].min():.4f}, {r['LUT_hot'].max():.4f}]",
            f"  mu_visc range:  [{r['LUT_mu_visc_hot'].min():.4f}, {r['LUT_mu_visc_hot'].max():.4f}]",
            f"  mu_adh range:   [{r['LUT_mu_adh_hot'].min():.4f}, {r['LUT_mu_adh_hot'].max():.4f}]",
            f"  A/A0 range:    [{r['LUT_A_A0_hot'].min():.6f}, {r['LUT_A_A0_hot'].max():.6f}]",
            "",
            "── 하중별 검증 (Cold Branch) ──",
        ]

        # Per-pressure breakdown for verification
        for i_p, p0 in enumerate(p0_arr):
            cold_slice = r['LUT_cold'][:, i_p, :]
            visc_slice = r['LUT_mu_visc_cold'][:, i_p, :]
            adh_slice = r['LUT_mu_adh_cold'][:, i_p, :]
            aa0_slice = r['LUT_A_A0_cold'][:, i_p, :]
            hot_slice = r['LUT_hot'][:, i_p, :]
            lines.append(f"  p0={p0:.3g} MPa:")
            lines.append(f"    mu_total: [{cold_slice.min():.4f}, {cold_slice.max():.4f}]  "
                         f"(peak={cold_slice.max():.4f})")
            lines.append(f"    mu_visc:  [{visc_slice.min():.4f}, {visc_slice.max():.4f}]")
            lines.append(f"    mu_adh:   [{adh_slice.min():.4f}, {adh_slice.max():.4f}]")
            lines.append(f"    A/A0:     [{aa0_slice.min():.6f}, {aa0_slice.max():.6f}]")
            lines.append(f"    mu_hot:   [{hot_slice.min():.4f}, {hot_slice.max():.4f}]")
            lines.append("")

        # Per-pressure A/A0 및 mu 성분 상세 비교
        if len(p0_arr) >= 2:
            lines.append("── 하중별 A/A0, μ_adh, μ_visc 상세 비교 ──")
            i_T_mid = len(T_arr) // 2
            i_v_mid = len(v_arr) // 2
            lines.append(f"  T0={T_arr[i_T_mid]:.0f}°C, v={v_arr[i_v_mid]:.2e} m/s 기준:")
            lines.append(f"  {'p0(MPa)':>10} {'A/A0':>12} {'μ_adh':>12} {'μ_visc':>12} {'μ_total':>12}")
            for i_p, p0 in enumerate(p0_arr):
                aa0_val = r['LUT_A_A0_cold'][i_T_mid, i_p, i_v_mid]
                mu_adh_val = r['LUT_mu_adh_cold'][i_T_mid, i_p, i_v_mid]
                mu_visc_val = r['LUT_mu_visc_cold'][i_T_mid, i_p, i_v_mid]
                mu_total_val = r['LUT_cold'][i_T_mid, i_p, i_v_mid]
                lines.append(
                    f"  {p0:>10.3g} {aa0_val:>12.6f} {mu_adh_val:>12.6f} "
                    f"{mu_visc_val:>12.6f} {mu_total_val:>12.6f}")
            lines.append("")

        lines.append(f"계산 시간: {elapsed:.1f}s")

        self.fm_result_text.config(state=tk.NORMAL)
        self.fm_result_text.delete('1.0', tk.END)
        self.fm_result_text.insert('1.0', '\n'.join(lines))
        self.fm_result_text.config(state=tk.DISABLED)

    def _export_friction_map_csv(self):
        """Export friction map LUT to CSV files."""
        from tkinter import filedialog

        r = self.friction_map_results
        if r is None:
            self._show_status("Friction Map 결과가 없습니다. 먼저 생성하세요.", 'warning')
            return

        filepath = filedialog.asksaveasfilename(
            title="Friction Map LUT 저장",
            defaultextension=".csv",
            filetypes=[("CSV files", "*.csv"), ("All files", "*.*")]
        )
        if not filepath:
            return

        try:
            T_arr = r['T_array']
            p0_arr = r['p0_array_MPa']
            v_arr = r['v_array']

            lines = [
                "# Friction Map 3D LUT",
                f"# T0_array_C: {','.join(f'{t:.1f}' for t in T_arr)}",
                f"# p0_array_MPa: {','.join(f'{p:.3f}' for p in p0_arr)}",
                f"# v_array_m/s: {len(v_arr)} points (logspace {np.log10(v_arr[0]):.1f} to {np.log10(v_arr[-1]):.1f})",
                "#",
                "# Format: T0[C],p0[MPa],v[m/s],mu_cold,mu_hot,mu_visc_cold,mu_visc_hot,mu_adh_cold,mu_adh_hot,A_A0_cold,A_A0_hot",
                "T0_C,p0_MPa,v_m_s,mu_cold,mu_hot,mu_visc_cold,mu_visc_hot,mu_adh_cold,mu_adh_hot,A_A0_cold,A_A0_hot",
            ]

            for i_T, T0 in enumerate(T_arr):
                for i_p, p0 in enumerate(p0_arr):
                    for i_v, v in enumerate(v_arr):
                        lines.append(
                            f"{T0:.1f},{p0:.3f},{v:.6e},"
                            f"{r['LUT_cold'][i_T,i_p,i_v]:.6f},{r['LUT_hot'][i_T,i_p,i_v]:.6f},"
                            f"{r['LUT_mu_visc_cold'][i_T,i_p,i_v]:.6f},{r['LUT_mu_visc_hot'][i_T,i_p,i_v]:.6f},"
                            f"{r['LUT_mu_adh_cold'][i_T,i_p,i_v]:.6f},{r['LUT_mu_adh_hot'][i_T,i_p,i_v]:.6f},"
                            f"{r['LUT_A_A0_cold'][i_T,i_p,i_v]:.6f},{r['LUT_A_A0_hot'][i_T,i_p,i_v]:.6f}"
                        )

            with open(filepath, 'w', encoding='utf-8-sig') as f:
                f.write('\n'.join(lines))

            self._show_status(f"Friction Map CSV 저장 완료: {filepath}", 'success')
        except Exception as e:
            from tkinter import messagebox
            messagebox.showerror("오류", f"CSV 저장 실패:\n{str(e)}")

    def _send_friction_map_to_ref(self):
        """Send selected (T, p0) friction map slice to mu_visc reference editor."""
        r = self.friction_map_results
        if r is None:
            self._show_status("Friction Map 결과가 없습니다. 먼저 생성하세요.", 'warning')
            return

        try:
            T_sel = float(self.fm_export_T_var.get())
            p0_sel = float(self.fm_export_p0_var.get())
        except ValueError:
            self._show_status("온도와 압력을 선택하세요.", 'warning')
            return

        T_arr = r['T_array']
        p0_arr_MPa = r['p0_array_MPa']
        v_arr = r['v_array']

        i_T = int(np.argmin(np.abs(T_arr - T_sel)))
        i_p = int(np.argmin(np.abs(p0_arr_MPa - p0_sel)))

        T_actual = T_arr[i_T]
        p0_actual = p0_arr_MPa[i_p]

        branch = self.fm_export_branch_var.get()
        visc_only = self.fm_export_visc_only_var.get()
        log_v = np.log10(np.maximum(v_arr, 1e-20)).tolist()

        from datetime import datetime
        saved_datasets = self._load_saved_datasets()

        branches_to_export = []
        if branch in ('cold', 'both'):
            branches_to_export.append('cold')
        if branch in ('hot', 'both'):
            branches_to_export.append('hot')

        names_added = []
        for br in branches_to_export:
            if visc_only:
                mu_data = r[f'LUT_mu_visc_{br}'][i_T, i_p, :]
            else:
                mu_data = r[f'LUT_{br}'][i_T, i_p, :]
            area_data = r[f'LUT_A_A0_{br}'][i_T, i_p, :]

            suffix = "visc" if visc_only else "total"
            ds_name = f"FM_{br}_{T_actual:.0f}C_{p0_actual:.3g}MPa_{suffix}"

            ds_entry = {
                'mu_log_v': log_v,
                'mu_vals': mu_data.tolist(),
                'area_log_v': log_v,
                'area_vals': area_data.tolist(),
                'saved_date': datetime.now().strftime('%Y-%m-%d %H:%M'),
                'source': f'FrictionMap T={T_actual:.0f}°C p0={p0_actual:.3g}MPa {br}'
            }

            saved_datasets[ds_name] = ds_entry

            # Also add to plotted_ref_datasets for immediate display
            if not hasattr(self, 'plotted_ref_datasets'):
                self.plotted_ref_datasets = []
            self.plotted_ref_datasets.append({
                'name': ds_name,
                'mu_log_v': log_v,
                'mu_vals': mu_data.tolist(),
                'area_log_v': log_v,
                'area_vals': area_data.tolist(),
            })
            names_added.append(ds_name)

        self._save_datasets_to_file(saved_datasets)

        # Refresh mu_visc plots if they exist
        try:
            if hasattr(self, 'mu_visc_results') and self.mu_visc_results is not None:
                v = self.mu_visc_results.get('v')
                mu = self.mu_visc_results.get('mu')
                details = self.mu_visc_results.get('details')
                if v is not None and mu is not None and details is not None:
                    use_nl = self.mu_use_fg_var.get() if hasattr(self, 'mu_use_fg_var') else False
                    self._update_mu_visc_plots(v, mu, details, use_nonlinear=use_nl)
        except Exception:
            pass

        names_str = "\n".join(f"  - {n}" for n in names_added)
        self._show_status(
            f"μ_visc 참조편집에 전송 완료:\n{names_str}\n\n"
            f"μ_visc 탭의 '참조 편집'에서 확인 가능합니다.", 'success')
        print(f"[FrictionMap→Ref] {len(names_added)} datasets saved: {names_added}")

    def get_friction_map_interpolator(self, branch='cold'):
        """Return a 3D interpolator for the friction map LUT.

        This can be used by the 2D Brush Model to look up friction
        coefficients at arbitrary (T0, p0, v) points.

        Args:
            branch: 'cold' or 'hot'

        Returns:
            scipy.interpolate.RegularGridInterpolator or None
        """
        from scipy.interpolate import RegularGridInterpolator

        r = self.friction_map_results
        if r is None:
            return None

        T_arr = r['T_array']
        p0_arr = r['p0_array_Pa']
        v_arr = r['v_array']
        LUT = r['LUT_cold'] if branch == 'cold' else r['LUT_hot']

        return RegularGridInterpolator(
            (T_arr, p0_arr, v_arr), LUT,
            method='linear', bounds_error=False, fill_value=None
        )

